import glossaryData from "@/data/glossary.json";

export type GlossaryDifficulty = "Débutant" | "Intermédiaire" | "Avancé";

export type GlossaryCategory =
  | "Fondamentaux"
  | "Wallets & sécurité"
  | "DeFi"
  | "Trading"
  | "Régulation FR"
  | "NFT/Web3"
  | "Layer 1/2";

export interface GlossaryTerm {
  id: string;
  term: string;
  category: GlossaryCategory;
  shortDefinition: string;
  longDefinition: string;
  synonyms: string[];
  relatedTerms: string[];
  example: string;
  difficulty: GlossaryDifficulty;
  lastUpdated: string;
}

const TERMS = (glossaryData as { terms: GlossaryTerm[] }).terms;

/** Tous les termes, triés par ordre alphabétique. */
export const GLOSSARY_TERMS: GlossaryTerm[] = [...TERMS].sort((a, b) =>
  a.term.localeCompare(b.term, "fr", { sensitivity: "base" })
);

/** Map id → term, pour résolution O(1). */
const TERMS_BY_ID = new Map(TERMS.map((t) => [t.id, t]));

export function getTermById(id: string): GlossaryTerm | undefined {
  return TERMS_BY_ID.get(id);
}

/** Catégories distinctes présentes dans le glossaire (ordre stable). */
export const GLOSSARY_CATEGORIES: GlossaryCategory[] = [
  "Fondamentaux",
  "Wallets & sécurité",
  "DeFi",
  "Trading",
  "Régulation FR",
  "NFT/Web3",
  "Layer 1/2",
];

/** Renvoie une lettre simple (A-Z) ou "#" si non alphabétique, en strippant accents. */
export function getInitial(term: string): string {
  const stripped = term
    .normalize("NFD")
    .replace(/\p{Diacritic}/gu, "")
    .toUpperCase();
  const first = stripped.charAt(0);
  return /[A-Z]/.test(first) ? first : "#";
}

/** Groupe les termes par lettre initiale, pour la page index alphabétique. */
export function groupByLetter(
  terms: GlossaryTerm[] = GLOSSARY_TERMS
): Record<string, GlossaryTerm[]> {
  return terms.reduce<Record<string, GlossaryTerm[]>>((acc, t) => {
    const letter = getInitial(t.term);
    (acc[letter] ||= []).push(t);
    return acc;
  }, {});
}

/** Construit le JSON-LD schema.org DefinedTerm pour une page de terme. */
export function buildDefinedTermSchema(term: GlossaryTerm, siteUrl: string) {
  return {
    "@context": "https://schema.org",
    "@type": "DefinedTerm",
    "@id": `${siteUrl}/glossaire/${term.id}`,
    name: term.term,
    description: term.shortDefinition,
    inDefinedTermSet: {
      "@type": "DefinedTermSet",
      name: "Glossaire crypto Cryptoreflex",
      url: `${siteUrl}/glossaire`,
    },
    url: `${siteUrl}/glossaire/${term.id}`,
    termCode: term.id,
    ...(term.synonyms.length > 0 ? { alternateName: term.synonyms } : {}),
  };
}

/* ============================================================================
 * GLOSSARY FLAT — Pilier 5 (page /outils/glossaire-crypto)
 * ----------------------------------------------------------------------------
 * Glossaire enrichi 200+ termes pour l'outil "Glossaire crypto français".
 * Type plat optimisé pour la recherche live + filtres catégorie côté Client.
 * Coexiste avec le glossaire long-form pré-existant (data/glossary.json),
 * qui sert les pages /glossaire/[slug] (SEO long-tail).
 * ========================================================================= */

export type GlossaryFlatCategory =
  | "Trading"
  | "DeFi"
  | "Sécurité"
  | "Régulation"
  | "NFT"
  | "Layer 2"
  | "Tokenomics"
  | "Wallet"
  | "Mining"
  | "Stablecoin";

export interface GlossaryTermFlat {
  /** Libellé canonique (français) — affiché tel quel. */
  term: string;
  /** Slug kebab-case unique (ancre HTML + URL future). */
  slug: string;
  /** Définition pédagogique 50-150 mots, sans markdown. */
  definition: string;
  /** Catégorie principale — pour les chips de filtre. */
  category: GlossaryFlatCategory;
  /** Slugs d'autres termes du glossaire à mettre en avant. */
  relatedTerms?: string[];
  /** Lien interne pertinent (page outil, comparatif, article). */
  internalLink?: string;
}

const _GLOSSARY_RAW: GlossaryTermFlat[] = [
  // ----- Fondamentaux & Trading basiques -----
  { term: "Blockchain", slug: "blockchain", category: "Trading", definition: "Registre numérique distribué et infalsifiable, répliqué sur des milliers d'ordinateurs. Chaque bloc contient l'empreinte cryptographique du précédent, ce qui rend toute modification rétroactive quasi impossible. Une blockchain publique (Bitcoin, Ethereum) est ouverte à tous, transparente et sans tiers de confiance. Les blockchains servent à enregistrer des transactions, exécuter des smart contracts ou tracer des actifs. Sans elle, aucune cryptomonnaie ne pourrait exister sans risque de double-dépense.", relatedTerms: ["bitcoin", "ethereum", "smart-contract", "noeud"], internalLink: "/outils" },
  { term: "Bitcoin", slug: "bitcoin", category: "Trading", definition: "Première cryptomonnaie de l'histoire, lancée en janvier 2009 par Satoshi Nakamoto. Bitcoin (BTC) est un réseau de paiement pair-à-pair sans banque ni État, fonctionnant sur une blockchain sécurisée par la preuve de travail (Proof of Work). L'offre est plafonnée à 21 millions d'unités, avec un halving tous les 4 ans qui divise par deux la création monétaire. Souvent surnommé « or numérique », BTC sert de réserve de valeur pour les investisseurs long terme.", relatedTerms: ["halving", "proof-of-work", "blockchain"] },
  { term: "Ethereum", slug: "ethereum", category: "Trading", definition: "Deuxième crypto par capitalisation, lancée en 2015 par Vitalik Buterin. Ethereum (ETH) est une blockchain programmable supportant les smart contracts et la quasi-totalité de l'écosystème DeFi, NFT et stablecoins. Depuis « The Merge » (sept. 2022), Ethereum tourne en Proof of Stake (consommation -99,9 %). ETH sert à payer les frais de transaction (gas) et peut être stake pour sécuriser le réseau et toucher un rendement.", relatedTerms: ["smart-contract", "gas-fees", "proof-of-stake", "staking"] },
  { term: "Altcoin", slug: "altcoin", category: "Trading", definition: "Toute cryptomonnaie autre que Bitcoin. Le terme regroupe Ethereum, Solana, BNB, XRP, Cardano et des milliers d'autres tokens. Les altcoins sont historiquement plus volatils que BTC : potentiel de gain plus élevé en bull market, drawdowns plus violents en bear market. La saison des altcoins (« altseason ») désigne les périodes où la dominance Bitcoin baisse au profit des autres cryptos.", relatedTerms: ["bitcoin", "shitcoin", "memecoin"] },
  { term: "Memecoin", slug: "memecoin", category: "Trading", definition: "Cryptomonnaie créée autour d'un meme ou d'une blague Internet, sans utilité technique fondamentale. Dogecoin, Shiba Inu, Pepe ou Bonk sont des memecoins emblématiques. Leur valeur dépend exclusivement de la spéculation, du buzz social et de la dynamique communautaire. Risque maximal : 90 % des memecoins disparaissent en moins d'un an. À réserver à une portion très marginale d'un portefeuille.", relatedTerms: ["altcoin", "shitcoin", "rugpull"] },
  { term: "Shitcoin", slug: "shitcoin", category: "Trading", definition: "Terme péjoratif désignant un projet crypto sans utilité réelle, sans équipe sérieuse ou conçu pour enrichir ses créateurs au détriment des acheteurs. Souvent associé aux pump-and-dump et rugpulls. Repérer un shitcoin : whitepaper vide, équipe anonyme sans track record, supply massive concentrée chez quelques wallets, marketing influenceur agressif.", relatedTerms: ["rugpull", "pump-and-dump", "memecoin"] },
  { term: "Whitepaper", slug: "whitepaper", category: "Tokenomics", definition: "Document fondateur d'un projet crypto qui décrit la vision, la technologie, le modèle économique et la tokenomics. Le whitepaper de Bitcoin (Satoshi Nakamoto, 2008) tient en 9 pages — c'est la référence absolue. Un whitepaper sérieux explique le problème résolu, l'architecture technique, la distribution des tokens et la roadmap. Whitepaper vide ou marketing = signal d'alerte majeur.", relatedTerms: ["tokenomics", "ico"], internalLink: "/outils/whitepaper-tldr" },
  { term: "Halving", slug: "halving", category: "Mining", definition: "Événement programmé tous les 210 000 blocs (environ 4 ans) qui divise par deux la récompense des mineurs Bitcoin. Le halving réduit l'inflation et renforce la rareté. Halvings passés : 2012, 2016, 2020, 2024 (récompense passée de 6,25 à 3,125 BTC). Historiquement suivi d'un cycle haussier 12 à 18 mois après. Le prochain halving aura lieu vers 2028.", relatedTerms: ["bitcoin", "mining", "tokenomics"], internalLink: "/halving-bitcoin" },
  { term: "Hard fork", slug: "hard-fork", category: "Tokenomics", definition: "Mise à jour majeure d'un protocole blockchain, incompatible avec la version précédente. Les nœuds qui n'upgradent pas sont éjectés. Un hard fork peut donner naissance à deux chaînes distinctes (Bitcoin / Bitcoin Cash en 2017, Ethereum / Ethereum Classic en 2016). Quand on détient une crypto au moment du fork, on reçoit généralement les tokens de la nouvelle chaîne.", relatedTerms: ["soft-fork", "consensus"] },
  { term: "Soft fork", slug: "soft-fork", category: "Tokenomics", definition: "Mise à jour rétro-compatible d'un protocole blockchain : les anciens nœuds continuent de fonctionner mais ne profitent pas des nouvelles règles. Plus douce qu'un hard fork, elle évite la création d'une chaîne parallèle. SegWit (2017) sur Bitcoin et Taproot (2021) sont des soft forks majeurs. Idéal pour patcher une faille ou ajouter une fonctionnalité sans diviser la communauté.", relatedTerms: ["hard-fork", "consensus"] },
  { term: "Mempool", slug: "mempool", category: "Mining", definition: "Salle d'attente des transactions en attente de validation par les mineurs. Lorsque vous envoyez une transaction, elle entre dans la mempool de chaque nœud avant d'être incluse dans un bloc. Plus la mempool est saturée, plus les frais grimpent : les mineurs priorisent les transactions les mieux rémunérées. Visible en temps réel via mempool.space pour Bitcoin.", relatedTerms: ["gas-fees", "mining", "block"] },
  { term: "Gas fees", slug: "gas-fees", category: "Trading", definition: "Frais de transaction payés au réseau pour exécuter une opération sur Ethereum (ou autre blockchain). Le « gas » mesure le coût computationnel ; le prix unitaire (en gwei) varie selon la congestion. Une transaction simple coûte 21 000 gas ; un swap DeFi 100 000 à 500 000 gas. Solutions pour réduire : Layer 2, batching, ou exécuter aux heures creuses.", relatedTerms: ["ethereum", "layer-2", "gwei"] },
  { term: "Gwei", slug: "gwei", category: "Trading", definition: "Sous-unité d'Ether utilisée pour exprimer le prix du gas. 1 ETH = 10⁹ gwei. Quand on dit « gas à 25 gwei », cela signifie qu'on paie 25 × 10⁻⁹ ETH par unité de gas consommée. Outils comme etherscan.io/gastracker affichent le prix actuel et historique. Pour optimiser, attendre les périodes off-peak (week-ends, nuits) où le gwei chute.", relatedTerms: ["gas-fees", "ethereum"] },
  { term: "Block", slug: "block", category: "Mining", definition: "Unité de base d'une blockchain : un ensemble de transactions horodatées et signées cryptographiquement, lié au bloc précédent par un hash. Bitcoin produit un bloc toutes les 10 minutes (1 Mo en moyenne) ; Ethereum un toutes les 12 secondes. Un bloc miné rapporte au mineur la récompense de bloc + les frais des transactions incluses.", relatedTerms: ["mining", "hash-rate", "blockchain"] },
  { term: "Hash rate", slug: "hash-rate", category: "Mining", definition: "Puissance de calcul totale dédiée au minage d'une blockchain Proof of Work, exprimée en hashs par seconde (TH/s, EH/s). Plus le hash rate est élevé, plus le réseau est sécurisé contre les attaques. Le hash rate de Bitcoin a dépassé 600 EH/s en 2024 — un niveau quasi inattaquable. Indicateur clé de santé du réseau et de confiance des mineurs.", relatedTerms: ["proof-of-work", "mining", "bitcoin"] },
  { term: "Mining", slug: "mining", category: "Mining", definition: "Processus de validation des transactions Proof of Work par calcul intensif. Les mineurs cherchent un hash valide pour clôturer un bloc et empochent la récompense (bloc + frais). Bitcoin mining se fait via des ASIC ultra-spécialisés ; minage CPU/GPU encore viable sur Monero, Ravencoin. Activité énergivore, controversée, mais qui sécurise la chaîne.", relatedTerms: ["proof-of-work", "hash-rate", "asic"] },
  { term: "Mineur", slug: "mineur", category: "Mining", definition: "Acteur qui exploite du matériel informatique pour valider les blocs d'une blockchain Proof of Work. En échange, il reçoit la récompense de bloc (3,125 BTC sur Bitcoin post-halving 2024) plus les frais de transaction. Les mineurs s'organisent en pools (Foundry, AntPool, F2Pool) pour lisser leurs revenus. Concurrence rude : ROI dépend du prix BTC, du coût électrique et de l'efficacité de l'ASIC.", relatedTerms: ["mining", "asic", "pool"] },
  { term: "ASIC", slug: "asic", category: "Mining", definition: "Application-Specific Integrated Circuit. Puce spécialisée optimisée pour une tâche unique — sur Bitcoin, le calcul du hash SHA-256. Bien plus rapide et économe qu'un GPU. Les principaux fabricants : Bitmain (Antminer), MicroBT (Whatsminer). Un ASIC moderne (Antminer S21) atteint 200 TH/s. Inutilisable hors mining, valeur de revente très volatile.", relatedTerms: ["mining", "mineur", "hash-rate"] },
  { term: "Proof of Work", slug: "proof-of-work", category: "Mining", definition: "Mécanisme de consensus historique inventé par Bitcoin. Les mineurs prouvent leur engagement en dépensant de l'électricité pour résoudre un puzzle cryptographique. Coûteux mais ultra-sécurisé : attaquer le réseau coûterait des milliards. Utilisé par BTC, Litecoin, Dogecoin, Monero. Critiqué pour son empreinte énergétique (~0,5 % conso mondiale d'élec).", relatedTerms: ["mining", "consensus", "proof-of-stake"] },
  { term: "Proof of Stake", slug: "proof-of-stake", category: "Tokenomics", definition: "Mécanisme de consensus alternatif où les validateurs sécurisent le réseau en immobilisant (« staking ») leurs tokens. Plus on stake, plus on a de chances de valider un bloc et toucher des récompenses. Beaucoup moins énergivore que le Proof of Work (-99,9 %). Utilisé par Ethereum (depuis The Merge), Solana, Cardano, Avalanche, Polkadot.", relatedTerms: ["staking", "validator", "ethereum"] },
  { term: "Validator", slug: "validator", category: "Tokenomics", definition: "Acteur qui sécurise une blockchain Proof of Stake en stakant un montant minimum de tokens. Sur Ethereum, il faut 32 ETH pour devenir validator solo. Les validators valident les blocs et touchent des récompenses (~3-5 % APR sur ETH). En cas de mauvais comportement (double-signing, downtime prolongé), une partie du stake est slashée.", relatedTerms: ["staking", "slashing", "proof-of-stake"] },
  { term: "Slashing", slug: "slashing", category: "Tokenomics", definition: "Pénalité automatique appliquée à un validator Proof of Stake malhonnête ou défaillant : une partie de son stake est détruite. Sur Ethereum, le slashing peut atteindre 1 ETH minimum, voire l'intégralité du stake en cas de violation grave (double-signing). Mécanisme essentiel pour aligner les incitations économiques avec la sécurité du réseau.", relatedTerms: ["validator", "staking", "proof-of-stake"] },
  { term: "Consensus", slug: "consensus", category: "Tokenomics", definition: "Algorithme par lequel les nœuds d'une blockchain s'accordent sur l'état officiel du registre. Sans consensus, double-dépense possible. Familles principales : Proof of Work (Bitcoin), Proof of Stake (Ethereum, Solana), Delegated PoS, BFT (Tendermint, Cosmos). Chacun arbitre différemment entre décentralisation, sécurité et scalabilité (le « trilemme blockchain »).", relatedTerms: ["proof-of-work", "proof-of-stake", "noeud"] },
  { term: "Nœud", slug: "noeud", category: "Tokenomics", definition: "Ordinateur qui participe à un réseau blockchain en hébergeant une copie complète (full node) ou partielle (light node) du registre. Les full nodes vérifient toutes les transactions et propagent les blocs ; les light nodes font confiance aux full nodes. Faire tourner son propre nœud Bitcoin = trustless validation + censorship resistance.", relatedTerms: ["blockchain", "consensus"] },
  // ----- Wallets & Sécurité -----
  { term: "Wallet", slug: "wallet", category: "Wallet", definition: "Portefeuille numérique qui stocke vos clés privées et permet de signer les transactions blockchain. Il n'« héberge » pas vos cryptos — celles-ci vivent sur la blockchain — mais l'accès à vos fonds dépend exclusivement de vos clés. Trois grandes familles : custodial (la plateforme garde les clés), non-custodial (vous gardez les clés), hardware (clés isolées sur un appareil dédié).", relatedTerms: ["cold-wallet", "hot-wallet", "seed-phrase"] },
  { term: "Cold wallet", slug: "cold-wallet", category: "Wallet", definition: "Portefeuille hors-ligne, déconnecté d'Internet : hardware wallet (Ledger, Trezor) ou paper wallet. Sécurité maximale contre le hacking en ligne. À utiliser pour stocker la majorité de son patrimoine crypto sur le long terme. Trade-off : moins pratique pour les transactions fréquentes. Règle d'or : tout au-delà de 1000-2000 € → cold wallet.", relatedTerms: ["hot-wallet", "hardware-wallet", "ledger"] },
  { term: "Hot wallet", slug: "hot-wallet", category: "Wallet", definition: "Portefeuille connecté à Internet : application mobile (Trust Wallet, Metamask), extension navigateur, ou web wallet. Pratique pour le trading actif et les interactions DeFi quotidiennes. Risque accru : exposé aux phishing, malwares et attaques smart contract. À limiter aux montants de « caisse courante » (semaine/mois), pas son patrimoine.", relatedTerms: ["cold-wallet", "metamask", "phantom"] },
  { term: "Hardware wallet", slug: "hardware-wallet", category: "Wallet", definition: "Appareil physique dédié au stockage des clés privées (Ledger Nano X, Trezor Model T, Coldcard). Les clés ne quittent jamais l'appareil — la signature se fait à l'intérieur, isolée du PC potentiellement compromis. Coût : 60-200 €. Indispensable dès qu'on dépasse 1-2 k€. Acheter exclusivement chez le fabricant officiel pour éviter les versions vérolées.", relatedTerms: ["cold-wallet", "ledger", "trezor"] },
  { term: "Ledger", slug: "ledger", category: "Wallet", definition: "Fabricant français de hardware wallets (Ledger Nano S Plus, Nano X, Stax). Référence du marché avec plus de 7 millions d'appareils vendus. Application Ledger Live pour gérer 5500+ cryptos. Polémiques récentes (Recover) mais reste le standard. Acheter UNIQUEMENT sur ledger.com pour éviter les arnaques.", relatedTerms: ["hardware-wallet", "trezor", "cold-wallet"] },
  { term: "Trezor", slug: "trezor", category: "Wallet", definition: "Pionnier des hardware wallets, lancé en 2014 par SatoshiLabs (République tchèque). Modèles : Trezor One (entrée de gamme) et Model T (écran tactile). Open-source intégral, contrairement à Ledger. Compatible avec 9000+ cryptos via apps tierces (Exodus, Electrum). Excellente alternative pour les puristes anti-fermé.", relatedTerms: ["hardware-wallet", "ledger", "cold-wallet"] },
  { term: "Metamask", slug: "metamask", category: "Wallet", definition: "Hot wallet le plus utilisé sur Ethereum et chaînes EVM (Polygon, Arbitrum, BNB Chain). Extension navigateur + app mobile. Indispensable pour interagir avec la DeFi, mint des NFT ou se connecter à des dApps. À sécuriser avec un mot de passe fort + seed phrase backupée hors ligne. Ne jamais saisir sa seed sur un site web.", relatedTerms: ["hot-wallet", "ethereum", "dapp"] },
  { term: "Phantom", slug: "phantom", category: "Wallet", definition: "Wallet phare de l'écosystème Solana, désormais multi-chain (SOL, ETH, Bitcoin, Polygon). Interface premium, intégré aux principales dApps Solana (Jupiter, Magic Eden). Disponible en extension et mobile. Permet swap intra-wallet, gestion NFT, staking SOL en quelques clics.", relatedTerms: ["hot-wallet", "solana"] },
  { term: "Seed phrase", slug: "seed-phrase", category: "Sécurité", definition: "Suite de 12 ou 24 mots générée aléatoirement qui permet de régénérer toutes les clés privées d'un wallet. C'est la clé maîtresse absolue — qui possède la seed possède les fonds. À écrire sur papier (jamais en numérique, jamais en photo, jamais cloud), à stocker dans un endroit sûr (coffre, double localisation). Personne, JAMAIS, ne doit demander votre seed.", relatedTerms: ["wallet", "private-key", "cold-storage"] },
  { term: "Private key", slug: "private-key", category: "Sécurité", definition: "Clé cryptographique secrète qui prouve la propriété d'une adresse blockchain et permet de signer les transactions. Format : 64 caractères hexadécimaux ou 256 bits aléatoires. La perdre = perdre l'accès aux fonds définitivement. La leak = voir ses fonds vidés en quelques secondes. Stockée dans un wallet, idéalement hardware.", relatedTerms: ["public-key", "seed-phrase", "wallet"] },
  { term: "Public key", slug: "public-key", category: "Sécurité", definition: "Clé cryptographique dérivée mathématiquement de la clé privée, partageable sans risque. Sert à vérifier les signatures et à dériver l'adresse publique. Asymétrique : impossible de remonter à la clé privée à partir de la publique (algorithmes ECDSA / EdDSA). Base de tout le système crypto.", relatedTerms: ["private-key", "address", "wallet"] },
  { term: "Address", slug: "address", category: "Wallet", definition: "Identifiant unique d'un wallet sur une blockchain, dérivé de la clé publique. Format : Bitcoin = bc1q... (Bech32), Ethereum = 0x... (40 hex), Solana = base58. Toujours vérifier les premiers ET derniers caractères avant un envoi (les malwares « clipboard hijack » remplacent les adresses copiées). Une adresse n'est PAS sensible — la partager n'expose pas vos fonds.", relatedTerms: ["public-key", "wallet"] },
  { term: "Cold storage", slug: "cold-storage", category: "Sécurité", definition: "Pratique de stockage long terme des cryptos sur un support déconnecté d'Internet : hardware wallet, paper wallet, ou multisig hors ligne. Élimine les vecteurs d'attaque en ligne (phishing, malware, compromission exchange). Recommandé pour 80-90 % de son patrimoine crypto. À combiner avec géolocalisation multiple et redondance des seeds.", relatedTerms: ["cold-wallet", "hardware-wallet", "seed-phrase"] },
  { term: "Multisig", slug: "multisig", category: "Sécurité", definition: "Wallet qui exige plusieurs signatures pour valider une transaction (ex : 2-of-3, 3-of-5). Élimine le single point of failure. Idéal pour : trésorerie d'entreprise, héritage crypto, gros montants. Solutions : Gnosis Safe (Ethereum), Casa (Bitcoin), Sparrow + multisig BTC. Un peu plus complexe à mettre en place mais énorme gain de sécurité.", relatedTerms: ["wallet", "cold-storage"] },
  { term: "Phishing", slug: "phishing", category: "Sécurité", definition: "Arnaque visant à voler vos identifiants ou votre seed phrase via un faux site, faux email, faux Discord ou fausse extension. Premier vecteur de vol crypto. Règles : toujours taper l'URL à la main, jamais cliquer un lien d'email/DM, jamais saisir sa seed sur un site, vérifier le certificat SSL. Si quelque chose semble suspect, c'est suspect.", relatedTerms: ["seed-phrase", "scam"] },
  { term: "Rugpull", slug: "rugpull", category: "Sécurité", definition: "Arnaque où l'équipe d'un projet crypto disparaît avec les fonds des investisseurs. Variantes : retrait soudain de la liquidité, abandon du développement, dump massif des tokens fondateurs. Très commun sur les memecoins lancés sur Solana ou BNB Chain. Détection : équipe anonyme, supply concentrée, liquidité non lockée, tokenomics opaque.", relatedTerms: ["scam", "shitcoin", "memecoin"] },
  { term: "Scam", slug: "scam", category: "Sécurité", definition: "Terme générique pour toute arnaque crypto : phishing, rugpull, faux airdrops, faux supports techniques, schémas de Ponzi déguisés en yield, faux influenceurs. Le secteur crypto attire massivement les arnaqueurs car les transactions sont irréversibles. Régle d'or : si ça semble trop beau pour être vrai, c'est une arnaque.", relatedTerms: ["phishing", "rugpull", "ponzi"] },
  { term: "Pump and dump", slug: "pump-and-dump", category: "Sécurité", definition: "Manipulation de marché coordonnée : un groupe achète massivement une crypto à faible volume pour faire grimper le prix (« pump »), attire les retardataires via du buzz, puis vend en masse au sommet (« dump »), ruinant les nouveaux entrants. Très fréquent sur les microcaps. Illégal sur les marchés financiers traditionnels mais difficile à poursuivre en crypto.", relatedTerms: ["scam", "shitcoin"] },
  { term: "FOMO", slug: "fomo", category: "Trading", definition: "Fear Of Missing Out. Sentiment d'urgence qui pousse à acheter une crypto en pleine hausse par peur de rater l'opportunité. Pire ennemi de l'investisseur : on achète au sommet, on subit le retournement. Antidote : DCA programmé, plan d'investissement écrit, refuser toute décision impulsive après lecture d'un tweet ou d'une vidéo YouTube.", relatedTerms: ["fud", "hodl", "dca"] },
  { term: "FUD", slug: "fud", category: "Trading", definition: "Fear, Uncertainty and Doubt. Diffusion volontaire ou non de peur, d'incertitude et de doute pour faire baisser le prix d'une crypto. Tactique courante avant un achat groupé : faire paniquer, racheter au plus bas. Antidote : se baser sur des sources primaires (whitepaper, on-chain data, communiqués officiels), pas sur les rumeurs Twitter.", relatedTerms: ["fomo", "hodl"] },
  { term: "HODL", slug: "hodl", category: "Trading", definition: "Stratégie consistant à conserver ses cryptos sur le long terme malgré la volatilité. Issu d'une faute de frappe (« hold ») sur un forum Bitcoin en 2013, devenu un mantra. Repose sur l'idée que le marché crypto suit des cycles de 4 ans — vendre court terme c'est rater les hausses parabolic. À combiner avec un cold wallet.", relatedTerms: ["dca", "cold-wallet", "fomo"] },
  { term: "DCA", slug: "dca", category: "Trading", definition: "Dollar Cost Averaging. Stratégie qui consiste à investir un montant fixe (ex : 100 €) à intervalles réguliers (chaque semaine ou mois), peu importe le prix. Lisse la volatilité, supprime le risque de timing, évite les décisions émotionnelles. Stratégie n°1 recommandée aux débutants. Backtests : DCA Bitcoin sur 5 ans = surperformance large vs livret A.", relatedTerms: ["hodl", "fomo"], internalLink: "/outils/simulateur-dca" },
  { term: "ATH", slug: "ath", category: "Trading", definition: "All-Time High. Le plus haut prix historique atteint par une crypto. Bitcoin ATH : ~108 000 $ (déc. 2024). Ethereum ATH : ~4 800 $ (nov. 2021). Mesure psychologique majeure : passer un ATH déclenche souvent un rallye FOMO. Inversement, rester loin de l'ATH peut être un bon point d'entrée si les fondamentaux restent solides.", relatedTerms: ["atl", "bitcoin"] },
  { term: "ATL", slug: "atl", category: "Trading", definition: "All-Time Low. Le plus bas prix historique d'une crypto. Pour Bitcoin : 0,003 $ (juillet 2010). Concept moins utilisé que l'ATH car les vieilles cryptos ont des ATL ridiculement bas. Pour les nouveaux tokens, l'ATL post-listing est un indicateur de capitulation et parfois un point d'entrée intéressant pour le contrarian.", relatedTerms: ["ath", "bitcoin"] },
  { term: "Bull market", slug: "bull-market", category: "Trading", definition: "Marché haussier prolongé (plusieurs mois à 2 ans). En crypto, les bull markets sont historiquement post-halving Bitcoin (2013, 2017, 2021, 2024-2025). Caractéristiques : sentiment euphorique, médias mainstream qui parlent de crypto, altseason, ATH successifs. Phase où il faut commencer à prendre des profits par tranches.", relatedTerms: ["bear-market", "ath", "halving"] },
  { term: "Bear market", slug: "bear-market", category: "Trading", definition: "Marché baissier prolongé. En crypto, les bears suivent souvent un bull (2014-2015, 2018-2019, 2022-2023) avec des drawdowns de 70-90 %. Phase douloureuse mais cruciale : meilleur moment pour DCA, accumulation, et study technique. Les bears finissent toujours — historique 100 % de récupération sur Bitcoin.", relatedTerms: ["bull-market", "dca", "capitulation"] },
  { term: "Capitulation", slug: "capitulation", category: "Trading", definition: "Phase finale d'un bear market : abandon massif des investisseurs qui vendent à perte par épuisement émotionnel. Volume de vente extrême, sentiment au plus bas, médias annoncent « la mort du Bitcoin » (à chaque fois). Statistiquement, le bottom de marché se forme dans les semaines qui suivent une capitulation. Difficile à acheter émotionnellement.", relatedTerms: ["bear-market", "fud"] },
  { term: "Long", slug: "long", category: "Trading", definition: "Position d'achat : on parie sur la hausse du prix. Acheter spot = être long. Sur les futures/perpetuals, ouvrir un long avec levier amplifie les gains et les pertes. Les longs paient un funding rate aux shorts en marché haussier (et inversement). À distinguer du « long terme » (durée de détention).", relatedTerms: ["short", "leverage", "futures"] },
  { term: "Short", slug: "short", category: "Trading", definition: "Position de vente : on parie sur la baisse du prix. Impossible en spot pur (sauf vente d'un asset détenu) mais courant en futures/perpetuals via levier. Risqué : perte théoriquement illimitée si le prix monte. Stratégie pro qui demande discipline, stop-loss et compréhension du funding rate.", relatedTerms: ["long", "leverage", "futures"] },
  { term: "Leverage", slug: "leverage", category: "Trading", definition: "Effet de levier. Permet de trader un montant supérieur à son capital, en empruntant à la plateforme. Levier 10x : 1 000 € de marge contrôlent 10 000 € de position. Démultiplie gains ET pertes. Une variation adverse de 10 % liquide la position. À éviter pour les débutants ; les pros plafonnent rarement à plus de 3-5x.", relatedTerms: ["liquidation", "futures", "margin"] },
  { term: "Liquidation", slug: "liquidation", category: "Trading", definition: "Fermeture forcée d'une position à effet de levier quand le prix franchit le seuil de marge. La plateforme vend votre collatéral pour couvrir la dette. Sur les longs : une chute violente liquide en cascade. Liquidations massives = catalyseur fréquent de mèche violente. Suivre les liquidations en live : Coinglass.com.", relatedTerms: ["leverage", "margin", "futures"] },
  { term: "Margin", slug: "margin", category: "Trading", definition: "Capital immobilisé en garantie d'une position à effet de levier. Margin = (taille position) / (levier). Si la perte non-réalisée approche la margin, appel de marge ou liquidation. Cross-margin = toutes les positions partagent la même margin (risque mutualisé) ; isolated margin = chaque position a sa propre margin (risque cloisonné).", relatedTerms: ["leverage", "liquidation"] },
  { term: "Futures", slug: "futures", category: "Trading", definition: "Contrats à terme avec date d'échéance, négociés sur Binance, OKX, dYdX. Permet de spéculer sur la hausse ou la baisse d'une crypto sans la détenir. Levier jusqu'à 100x sur certaines plateformes (déconseillé). Existent aussi en perpétuels (sans date d'échéance), maintenus par un funding rate. Fiscalité française : régime trader pro probable.", relatedTerms: ["leverage", "perpetual", "options"] },
  { term: "Perpetual", slug: "perpetual", category: "Trading", definition: "Contrat futures sans date d'échéance, inventé par BitMEX en 2016. Le prix reste arrimé au spot via le funding rate : si perp > spot, les longs paient les shorts (et inversement). Permet de tenir une position théoriquement à vie. Volume monstrueux (>50 % du volume crypto). Plateformes : Binance, Bybit, Hyperliquid, dYdX.", relatedTerms: ["futures", "funding-rate", "leverage"] },
  { term: "Funding rate", slug: "funding-rate", category: "Trading", definition: "Mécanisme qui maintient le prix des perpétuels proche du spot. Toutes les 8h (généralement), longs ou shorts versent un % de leur position à l'autre côté. Funding positif = trop de longs, ils paient les shorts. Indicateur de sentiment : funding extrême = marché surchauffé, retournement probable.", relatedTerms: ["perpetual", "futures"] },
  { term: "Spot", slug: "spot", category: "Trading", definition: "Marché au comptant : on achète/vend la crypto réelle, livrée immédiatement dans son wallet. Par opposition aux dérivés (futures, options). Pas de levier (sauf margin trading), pas de liquidation, pas de funding. Approche recommandée à 99 % des investisseurs particuliers.", relatedTerms: ["futures", "leverage"] },
  { term: "Order book", slug: "order-book", category: "Trading", definition: "Carnet d'ordres : liste en temps réel des ordres d'achat (bids) et de vente (asks) sur une paire de trading. Le top du carnet = meilleur bid (le plus haut) et meilleur ask (le plus bas) ; spread = différence. Liquidité d'une paire = profondeur du carnet. Outil clé pour les traders actifs.", relatedTerms: ["spread", "liquidity"] },
  { term: "Spread", slug: "spread", category: "Trading", definition: "Différence entre le meilleur prix d'achat (bid) et le meilleur prix de vente (ask) sur un order book. Plus le spread est faible, plus la paire est liquide. Sur BTC/USDT chez Binance, spread quasi nul ; sur des microcaps illiquides, spread > 1 % qui se cumule à chaque trade. À surveiller absolument avant d'entrer en position.", relatedTerms: ["order-book", "liquidity", "slippage"] },
  { term: "Slippage", slug: "slippage", category: "Trading", definition: "Différence entre le prix attendu et le prix réel d'exécution d'un ordre. Causes : manque de liquidité, ordre trop gros, marché volatile. Sur les DEX, le slippage tolerance se règle manuellement (0,5-1 % standard, 5-10 % sur memecoins). Slippage trop large = porte ouverte au frontrunning MEV.", relatedTerms: ["spread", "liquidity", "mev"] },
  { term: "Liquidity", slug: "liquidity", category: "DeFi", definition: "Capacité d'acheter ou vendre une crypto sans impacter son prix. Mesurée par le volume quotidien, la profondeur du carnet d'ordres et le TVL (en DeFi). Liquidité élevée = exécution rapide, faible slippage. Liquidité faible = risque de manipulation, slippage massif, sortie compliquée. Privilégier les paires liquides (top 50 marketcap).", relatedTerms: ["liquidity-pool", "spread", "tvl"] },
  // ----- DeFi -----
  { term: "DeFi", slug: "defi", category: "DeFi", definition: "Decentralized Finance. Écosystème de produits financiers (prêts, échanges, rendements, dérivés, assurance) opérés par des smart contracts sans intermédiaire centralisé. Permet à quiconque ayant un wallet d'accéder à des services bancaires globaux, 24/7, sans KYC. Risques : hack de smart contract, exploit, rugpull, gouvernance compromise. TVL mondial : ~80 milliards $.", relatedTerms: ["dex", "yield-farming", "lending"] },
  { term: "DEX", slug: "dex", category: "DeFi", definition: "Decentralized Exchange. Plateforme d'échange opérée par smart contracts, sans gardien central des fonds. L'utilisateur garde ses cryptos dans son wallet et signe lui-même chaque trade. Modèles : AMM (Uniswap, Curve), order book on-chain (dYdX, Hyperliquid). Avantages : non-custodial, sans KYC. Inconvénients : gas fees, slippage, pas de fiat.", relatedTerms: ["cex", "amm", "uniswap"] },
  { term: "CEX", slug: "cex", category: "Trading", definition: "Centralized Exchange. Plateforme d'échange traditionnelle (Binance, Coinbase, Kraken, Bitget) qui agit comme tiers de confiance. KYC obligatoire, dépôts fiat, ordres limit/stop-loss, liquidité massive. Risque : la plateforme peut faire faillite (FTX 2022), être hackée, ou geler vos fonds. À utiliser pour acheter, pas pour stocker.", relatedTerms: ["dex", "kyc"] },
  { term: "AMM", slug: "amm", category: "DeFi", definition: "Automated Market Maker. Modèle d'échange décentralisé inventé par Uniswap : un smart contract gère une pool de deux tokens et calcule le prix selon une formule (x*y=k pour la constante product). Les utilisateurs swappent contre la pool, payent une fee aux liquidity providers. Révolution DeFi : trading 24/7 sans market maker humain.", relatedTerms: ["uniswap", "liquidity-pool", "dex"] },
  { term: "Liquidity pool", slug: "liquidity-pool", category: "DeFi", definition: "Réserve de deux tokens (ou plus) déposés dans un smart contract AMM, servant de contrepartie aux swaps. Les liquidity providers déposent à parts égales (50/50 généralement) et touchent une fraction des fees de trading + parfois des récompenses en token de gouvernance. Risque clé : impermanent loss si les prix divergent.", relatedTerms: ["amm", "impermanent-loss", "yield-farming"] },
  { term: "Impermanent loss", slug: "impermanent-loss", category: "DeFi", definition: "Perte non-réalisée subie par un liquidity provider quand le prix des tokens dans une pool diverge. Exemple : déposer 1 ETH + 3000 USDC ; si ETH passe à 6000 $, à la sortie on récupère moins d'ETH et plus d'USDC qu'au départ — moins de valeur que si on avait simplement HODL. Compensable par les fees collectées si la pool est très traded.", relatedTerms: ["liquidity-pool", "amm"] },
  { term: "Yield farming", slug: "yield-farming", category: "DeFi", definition: "Stratégie consistant à déplacer ses cryptos entre protocoles DeFi pour maximiser les rendements (intérêts + récompenses en tokens). Pratique née durant le « DeFi Summer » 2020 avec Compound. Rendements élevés (10-100 % APY) mais risques cumulés : smart contract, IL, dépréciation du token de récompense, gas fees.", relatedTerms: ["liquidity-pool", "apy", "lending"] },
  { term: "Staking", slug: "staking", category: "DeFi", definition: "Immobilisation de ses tokens pour sécuriser une blockchain Proof of Stake et toucher des récompenses (3-12 % APR selon le réseau). Staking solo (32 ETH min sur Ethereum), staking délégué (via un pool), liquid staking (Lido, Rocket Pool). Risques : slashing, durée de unbonding, dépréciation du token. Fiscalité FR : revenus assimilés à des plus-values.", relatedTerms: ["proof-of-stake", "validator", "liquid-staking"] },
  { term: "Liquid staking", slug: "liquid-staking", category: "DeFi", definition: "Variante du staking où l'on reçoit un token dérivé liquide (stETH chez Lido, rETH chez Rocket Pool) représentant l'ETH staké + les récompenses. Ce token est utilisable en DeFi (collateral, LP), permettant de cumuler les rendements. Lido détient ~30 % de l'ETH staké, soulevant des inquiétudes de centralisation.", relatedTerms: ["staking", "lido"] },
  { term: "Restaking", slug: "restaking", category: "DeFi", definition: "Innovation 2024 : utiliser de l'ETH déjà staké pour sécuriser d'autres protocoles (oracles, bridges, AVS) et toucher un rendement supplémentaire. EigenLayer est le pionnier. Multiplie les sources de yield mais aussi les vecteurs de slashing. Hype massif, à manier avec prudence : risque opérationnel cumulé.", relatedTerms: ["staking", "liquid-staking"] },
  { term: "Lending", slug: "lending", category: "DeFi", definition: "Prêt de cryptos via un protocole DeFi (Aave, Compound, Morpho). On dépose un asset, on touche un intérêt variable. Côté emprunteur, on dépose du collatéral (souvent 150 % de la valeur empruntée) et on reçoit l'asset emprunté. Sur-collatéralisé donc pas de credit check. Risque : liquidation si le collatéral chute.", relatedTerms: ["aave", "borrowing", "collateral"] },
  { term: "Borrowing", slug: "borrowing", category: "DeFi", definition: "Emprunt sur un protocole DeFi : on dépose un collatéral en crypto (ETH, BTC), on reçoit jusqu'à ~70 % de sa valeur en stablecoins. Permet d'utiliser sa crypto sans la vendre (et déclencher de la fiscalité). Si le ratio LTV monte trop, liquidation automatique. Stratégie pro pour cash-out sans vendre.", relatedTerms: ["lending", "collateral", "ltv"] },
  { term: "Collateral", slug: "collateral", category: "DeFi", definition: "Garantie déposée dans un protocole de lending pour obtenir un emprunt. Doit toujours valoir plus que le montant emprunté (sur-collatéralisation). Si la valeur du collatéral chute, liquidation. Cryptos acceptées : ETH, WBTC, stablecoins, tokens majeurs. Diversifier les collatéraux limite le risque de liquidation.", relatedTerms: ["lending", "liquidation", "ltv"] },
  { term: "LTV", slug: "ltv", category: "DeFi", definition: "Loan-to-Value. Ratio entre le montant emprunté et la valeur du collatéral. LTV maximum varie selon l'asset : ~80 % sur stablecoins, 70 % sur ETH/BTC, 50 % sur altcoins. Quand le LTV approche le maximum, risque de liquidation imminent. Bonne pratique : maintenir un LTV bas (40-50 %) pour absorber les drawdowns.", relatedTerms: ["lending", "collateral", "liquidation"] },
  { term: "Aave", slug: "aave", category: "DeFi", definition: "Protocole DeFi de lending/borrowing leader, multichain (Ethereum, Polygon, Arbitrum, Avalanche). TVL ~12 milliards $. Permet de déposer 30+ assets pour gagner des intérêts ou emprunter contre collatéral. Innovations : flash loans, isolation mode, GHO (stablecoin natif). Token gouvernance : AAVE.", relatedTerms: ["lending", "compound"] },
  { term: "Uniswap", slug: "uniswap", category: "DeFi", definition: "DEX pionnier inventeur du modèle AMM (2018). Volume cumulé > 2 trillions $. Versions successives : V2 (pools 50/50), V3 (concentrated liquidity, gain capital efficiency 4000x), V4 (hooks personnalisables). Token UNI sert à la gouvernance. Référence absolue de la DeFi sur Ethereum et chains EVM.", relatedTerms: ["amm", "dex", "liquidity-pool"] },
  { term: "Compound", slug: "compound", category: "DeFi", definition: "Protocole DeFi historique de lending (lancé 2018). A inventé le « yield farming » avec la distribution de COMP en 2020, déclenchant le DeFi Summer. Aujourd'hui dépassé par Aave en TVL, mais reste une référence du secteur. Compound III (Comet) propose des marchés isolés par asset.", relatedTerms: ["lending", "aave"] },
  { term: "Curve", slug: "curve", category: "DeFi", definition: "DEX spécialisé dans les swaps entre actifs similaires (stablecoins, dérivés ETH). Formule mathématique optimisée pour minimiser le slippage entre USDC/USDT/DAI. Token CRV gouverne via veCRV (vote-escrowed). Pivot historique de la « Curve Wars » entre protocoles cherchant à booster leurs pools.", relatedTerms: ["dex", "stablecoin", "amm"] },
  { term: "MakerDAO", slug: "makerdao", category: "DeFi", definition: "Protocole DeFi historique qui émet le stablecoin DAI, collatéralisé par des cryptos déposées. Mécanisme : déposer ETH/WBTC, frapper du DAI jusqu'à 66 % de la valeur. Si le ratio chute, vault liquidé. DAI est le stablecoin décentralisé le plus utilisé. Évolution récente : Sky Protocol, USDS.", relatedTerms: ["dai", "stablecoin", "lending"] },
  { term: "Lido", slug: "lido", category: "DeFi", definition: "Plus gros protocole de liquid staking ETH. Stake ETH pour vous, vous donne du stETH (token liquide rebasing avec les récompenses). Détient ~30 % de l'ETH staké total — controversé pour la centralisation. Disponible aussi sur Solana, Polygon. Token LDO pour la gouvernance.", relatedTerms: ["liquid-staking", "staking", "ethereum"] },
  { term: "Yearn", slug: "yearn", category: "DeFi", definition: "Agrégateur de yield DeFi qui automatise les stratégies de rendement entre Aave, Compound, Curve, etc. Vous déposez un asset, Yearn alloue automatiquement à la stratégie la plus rentable. Frais : 2/20 (2 % management, 20 % performance). Pionnier 2020, encore actif mais éclipsé par les nouveaux acteurs.", relatedTerms: ["yield-farming", "lending"] },
  { term: "Flash loan", slug: "flash-loan", category: "DeFi", definition: "Emprunt sans collatéral exécuté et remboursé dans la même transaction blockchain. Si le remboursement échoue, toute la transaction est annulée — risque zéro pour le prêteur. Usages légitimes : arbitrage, refinancement de positions. Souvent détourné pour exploiter des bugs de smart contracts (attaques flash loan).", relatedTerms: ["lending", "exploit"] },
  { term: "MEV", slug: "mev", category: "DeFi", definition: "Maximal Extractable Value. Profit qu'un mineur/validator peut extraire en réordonnant, incluant ou excluant des transactions dans un bloc. Pratiques : frontrunning, sandwich attacks, liquidations. Coûte ~700 M$/an aux utilisateurs Ethereum. Solutions : MEV-Boost, Flashbots Protect, Cowswap (protection sandwich).", relatedTerms: ["frontrunning", "validator"] },
  { term: "Frontrunning", slug: "frontrunning", category: "DeFi", definition: "Pratique où un acteur observe une transaction pending dans la mempool et soumet la sienne avec un gas plus élevé pour passer avant — typiquement pour profiter d'un gros achat qui va faire monter le prix. Forme commune du MEV. Plus prononcé sur les DEX. Solutions : Flashbots Protect, transactions privées.", relatedTerms: ["mev", "mempool", "sandwich-attack"] },
  { term: "Sandwich attack", slug: "sandwich-attack", category: "DeFi", definition: "Attaque MEV à 3 étapes : 1) le bot voit une grosse transaction de swap dans la mempool, 2) il achète le token avant pour faire monter le prix, 3) il revend après vous, empochant la différence. Victime : vous subissez un slippage anormal. Protection : transactions privées (Flashbots), slippage tolerance basse, DEX anti-MEV (Cowswap).", relatedTerms: ["mev", "frontrunning", "slippage"] },
  // ----- Stablecoins -----
  { term: "Stablecoin", slug: "stablecoin", category: "Stablecoin", definition: "Cryptomonnaie indexée sur la valeur d'un actif stable, généralement le dollar US (USDT, USDC, DAI). Permet d'éviter la volatilité crypto sans sortir vers le système bancaire. Trois familles : centralisé (USDT, USDC), décentralisé (DAI, FRAX), algorithmique (déconseillé après le crash UST). Fondamental pour DeFi, trading et remittances.", relatedTerms: ["usdt", "usdc", "dai"] },
  { term: "USDT", slug: "usdt", category: "Stablecoin", definition: "Tether. Premier stablecoin par capitalisation (~140 milliards $), émis par Tether Limited. Adossé au dollar via réserves cash + bons du Trésor + autres. Audit régulier mais transparence partiellement contestée. Utilisé sur 99 % des paires CEX et DeFi cross-chain. Liquidité mondiale incomparable.", relatedTerms: ["stablecoin", "usdc"] },
  { term: "USDC", slug: "usdc", category: "Stablecoin", definition: "USD Coin. Stablecoin émis par Circle (~40 milliards $), entièrement réservé en cash + bons du Trésor américains, audité mensuellement. Plus transparent que USDT mais légèrement moins liquide. Référence des entreprises et investisseurs institutionnels. Conforme MiCA depuis 2024.", relatedTerms: ["stablecoin", "usdt"] },
  { term: "DAI", slug: "dai", category: "Stablecoin", definition: "Stablecoin décentralisé émis par MakerDAO via sur-collatéralisation crypto (ETH, WBTC, USDC). Pegged au dollar par mécanismes de marché et de stability fee. ~5 milliards $ en circulation. Avantage : pas d'autorité centrale qui peut le freezer. Inconvénient : dépend d'USDC à ~60 %, ce qui contredit la décentralisation pure.", relatedTerms: ["makerdao", "stablecoin"] },
  { term: "FRAX", slug: "frax", category: "Stablecoin", definition: "Stablecoin hybride : partiellement collatéralisé (USDC), partiellement algorithmique (FXS). Le ratio s'ajuste dynamiquement selon la demande. Innovant mais a connu des stress tests durant la dépeg de l'USDC (mars 2023). Aujourd'hui s'oriente vers une version 100 % collatéralisée (FRAX V3).", relatedTerms: ["stablecoin", "dai"] },
  { term: "Depeg", slug: "depeg", category: "Stablecoin", definition: "Décrochage d'un stablecoin par rapport à son ancrage (ex : 1 USDC à 0,87 $ en mars 2023). Causes : crise bancaire (Silicon Valley Bank), perte de confiance, attaque coordonnée. Un dépeg crée des opportunités d'arbitrage mais aussi des paniques. Le crash de l'UST (Terra/Luna, mai 2022) reste l'exemple le plus dramatique.", relatedTerms: ["stablecoin", "usdc"] },
  { term: "CBDC", slug: "cbdc", category: "Régulation", definition: "Central Bank Digital Currency. Monnaie numérique émise par une banque centrale (Yuan numérique, euro numérique en projet). Pas une cryptomonnaie : centralisée, traçable, programmable, contrôlée par l'État. Suscite des débats sur la vie privée et la liberté financière. La BCE prévoit l'euro numérique pour 2026-2028.", relatedTerms: ["stablecoin", "mica"] },
  { term: "PayPal USD", slug: "paypal-usd", category: "Stablecoin", definition: "Stablecoin émis par PayPal (PYUSD), lancé en 2023. Adossé au dollar US, réserves chez Paxos. Utilisable dans l'écosystème PayPal et Venmo, transferable on-chain (Ethereum, Solana). Marketcap modeste (~1 milliard $) mais signal fort de l'adoption stablecoin par les fintechs traditionnelles.", relatedTerms: ["stablecoin", "usdc"] },
  { term: "Tether", slug: "tether", category: "Stablecoin", definition: "Société émettrice du stablecoin USDT. Basée aux Îles Vierges britanniques. Régulièrement controversée (manque de transparence, amende SEC 2021) mais demeure le poids lourd absolu du marché stablecoin. Génère plusieurs milliards $ de profits annuels grâce aux intérêts sur les bons du Trésor en réserve.", relatedTerms: ["usdt", "stablecoin"] },
  // ----- NFT -----
  { term: "NFT", slug: "nft", category: "NFT", definition: "Non-Fungible Token. Token unique et non-interchangeable représentant la propriété d'un actif numérique (image, vidéo, musique, item de jeu). Standard ERC-721 sur Ethereum. Marché en repli depuis le pic 2021 mais infrastructure solide. Cas d'usage durables : tickets, certificats, identité, gaming, RWA.", relatedTerms: ["erc-721", "opensea", "metadata"] },
  { term: "ERC-721", slug: "erc-721", category: "NFT", definition: "Standard de smart contract Ethereum pour les NFT non-fongibles. Chaque token a un ID unique. Utilisé par CryptoPunks, Bored Ape Yacht Club, Azuki. Implémenté en Solidity, code open-source. Le standard concurrent ERC-1155 permet à un contrat de gérer plusieurs NFT et tokens fongibles.", relatedTerms: ["nft", "erc-1155", "smart-contract"] },
  { term: "ERC-1155", slug: "erc-1155", category: "NFT", definition: "Standard de smart contract « semi-fongible » créé par Enjin. Un seul contrat peut gérer plusieurs types de tokens (NFT et fungibles). Plus efficace en gas pour les jeux qui ont des milliers d'items. Utilisé par OpenSea, Sandbox, et les principaux jeux blockchain.", relatedTerms: ["erc-721", "nft", "smart-contract"] },
  { term: "OpenSea", slug: "opensea", category: "NFT", definition: "Marketplace NFT historique, lancée en 2017. A dominé 2021-2022 avec >90 % du volume. Aujourd'hui concurrencée par Blur (sur Ethereum) et Magic Eden (sur Solana). Frais : 2,5 % par transaction. Multi-chain : Ethereum, Polygon, Arbitrum, Solana.", relatedTerms: ["nft", "magic-eden"] },
  { term: "Magic Eden", slug: "magic-eden", category: "NFT", definition: "Marketplace NFT leader sur Solana, étendue à Bitcoin (Ordinals) et Ethereum. Plus de 30 millions d'utilisateurs cumulés. Interface premium, frais bas (2 %), royalties optionnelles. Devenue le hub des memecoins NFT et des collections gaming Solana.", relatedTerms: ["opensea", "nft", "solana"] },
  { term: "Mint", slug: "mint", category: "NFT", definition: "Création d'un nouveau NFT en l'inscrivant sur la blockchain. Le mint coûte du gas. Pour une collection (ex : 10 000 NFT), le mint se fait soit par les créateurs (lazy minting), soit par les acheteurs en pré-vente. Mints très demandés : congestion gas, frontrunning, FOMO. Mints flopés : projet probablement mort.", relatedTerms: ["nft", "gas-fees"] },
  { term: "Floor price", slug: "floor-price", category: "NFT", definition: "Prix le plus bas auquel un NFT d'une collection est listé en vente. Indicateur clé de santé d'une collection. CryptoPunks floor : ~30 ETH ; BAYC : ~10 ETH (en 2025). Suivi en live sur OpenSea, Blur, Magic Eden. Une chute de floor = sentiment négatif ; une remontée = renouveau d'intérêt.", relatedTerms: ["nft", "opensea"] },
  { term: "Royalties", slug: "royalties", category: "NFT", definition: "Pourcentage versé au créateur d'un NFT à chaque revente sur le marché secondaire (typiquement 2,5-10 %). Système rendu optionnel par Blur en 2023, ce qui a divisé l'écosystème : artistes contre traders. Aujourd'hui, les royalties on-chain enforced (ERC-2981) gagnent du terrain.", relatedTerms: ["nft", "opensea"] },
  { term: "Metadata", slug: "metadata", category: "NFT", definition: "Données associées à un NFT décrivant son contenu : image, attributs, traits. Stockées soit on-chain (rare, cher, immuable), soit off-chain via IPFS (décentralisé) ou serveur centralisé (risqué : si le serveur disparaît, le NFT devient une URL morte). Privilégier IPFS pour la pérennité.", relatedTerms: ["nft", "ipfs"] },
  { term: "IPFS", slug: "ipfs", category: "NFT", definition: "InterPlanetary File System. Protocole de stockage distribué pair-à-pair, alternative décentralisée à HTTP. Utilisé pour stocker la metadata et les médias des NFT. Adresse contenu via hash (CID) — si le fichier change, l'adresse change. Pour la persistance, payer un service de pinning (Pinata, Infura).", relatedTerms: ["metadata", "nft"] },
  { term: "PFP", slug: "pfp", category: "NFT", definition: "Profile Picture. Catégorie de NFT utilisée comme avatar (CryptoPunks, BAYC, Azuki, Pudgy Penguins). Sert d'identité sociale dans la crypto-twittersphère. Bulle 2021-2022 puis effondrement, mais quelques collections « blue chips » conservent une valeur résiduelle significative.", relatedTerms: ["nft", "cryptopunks"] },
  { term: "Ordinals", slug: "ordinals", category: "NFT", definition: "Innovation 2023 permettant d'inscrire des images, textes ou code sur les satoshis individuels de Bitcoin — créant des NFT natifs Bitcoin. Mouvement controversé (saturation mempool, hausse fees) mais a relancé l'innovation sur BTC. A donné naissance aux BRC-20 et Runes.", relatedTerms: ["bitcoin", "nft", "brc-20"] },
  { term: "BRC-20", slug: "brc-20", category: "NFT", definition: "Standard expérimental de tokens fongibles sur Bitcoin via Ordinals. Permet de créer des « memecoins » sur BTC (ex : ORDI). Très inefficace en termes de gas/blockchain bloat — depuis remplacé par les Runes (avril 2024) plus optimisé.", relatedTerms: ["ordinals", "bitcoin", "runes"] },
  { term: "Runes", slug: "runes", category: "NFT", definition: "Standard de tokens fongibles sur Bitcoin lancé au halving 2024 par Casey Rodarmor (créateur des Ordinals). Plus efficace que BRC-20 en termes de blockchain footprint. A généré une vague de memecoins BTC. Adoption en cours de stabilisation post-hype initial.", relatedTerms: ["ordinals", "brc-20", "bitcoin"] },
  // ----- Layer 1 / Layer 2 -----
  { term: "Layer 1", slug: "layer-1", category: "Layer 2", definition: "Blockchain de base, autonome et souveraine, qui valide ses propres transactions (Bitcoin, Ethereum, Solana, Avalanche, BNB Chain). Sécurité maximale mais throughput limité (15 TPS sur ETH L1). Historiquement, les L1 se concurrencent sur le trilemme : décentralisation, sécurité, scalabilité.", relatedTerms: ["layer-2", "ethereum", "solana"] },
  { term: "Layer 2", slug: "layer-2", category: "Layer 2", definition: "Blockchain construite par-dessus une Layer 1 (généralement Ethereum) pour augmenter le throughput et baisser les frais, tout en héritant de la sécurité de la L1. Familles : Optimistic Rollups (Arbitrum, Optimism, Base), ZK-Rollups (zkSync, Linea, Scroll, Starknet). Frais 10-100x inférieurs à L1.", relatedTerms: ["rollup", "arbitrum", "optimism", "ethereum"] },
  { term: "Rollup", slug: "rollup", category: "Layer 2", definition: "Type de Layer 2 qui exécute les transactions hors-chaîne puis les compresse et les soumet à la L1 sous forme d'un seul bundle de preuves. Sépare exécution (rapide, off-chain) et settlement (L1 sécurisé). Deux écoles : Optimistic (prouve-moi le contraire) et ZK (prouve mathématiquement).", relatedTerms: ["layer-2", "optimistic-rollup", "zk-rollup"] },
  { term: "Optimistic Rollup", slug: "optimistic-rollup", category: "Layer 2", definition: "Rollup qui suppose que les transactions sont valides par défaut, avec une période de challenge de 7 jours pendant laquelle quiconque peut prouver une fraude (fraud proof). Plus simple à implémenter que les ZK. Exemples : Arbitrum, Optimism, Base, Mantle. Inconvénient : retrait vers L1 long (7j).", relatedTerms: ["rollup", "zk-rollup", "arbitrum"] },
  { term: "ZK-Rollup", slug: "zk-rollup", category: "Layer 2", definition: "Rollup qui utilise des preuves cryptographiques (Zero-Knowledge proofs) pour prouver mathématiquement la validité des transactions. Aucune période de challenge — retrait instantané vers L1. Plus complexe à implémenter. Exemples : zkSync, Linea, Scroll, Starknet, Polygon zkEVM. Considéré comme le futur des L2.", relatedTerms: ["rollup", "optimistic-rollup", "zero-knowledge"] },
  { term: "Zero Knowledge", slug: "zero-knowledge", category: "Layer 2", definition: "Cryptographie permettant de prouver qu'on connaît une information sans la révéler. Base des ZK-Rollups, des solutions de confidentialité (Aztec, Aleo) et de l'identité digitale décentralisée. Innovation majeure 2023-2025 : ZK-EVM, ZK-VM, recursive proofs. Promet un Web décentralisé scalable et privé.", relatedTerms: ["zk-rollup", "rollup"] },
  { term: "Arbitrum", slug: "arbitrum", category: "Layer 2", definition: "L2 Ethereum dominante par TVL (~12 milliards $). Optimistic Rollup. Compatible EVM, écosystème DeFi très riche (GMX, Camelot, Pendle). Frais 10-30x inférieurs à Ethereum L1. Token ARB lancé en 2023 via airdrop massif. Variante : Arbitrum Nova pour les apps gaming/social.", relatedTerms: ["optimistic-rollup", "layer-2", "ethereum"] },
  { term: "Optimism", slug: "optimism", category: "Layer 2", definition: "L2 Ethereum, optimistic rollup, créateur du « OP Stack » utilisé par Base, Mantle, Mode, Worldcoin. Token OP, gouvernance via le « Collective » (Token House + Citizens House). Vision : Superchain (réseau de L2 interconnectées). TVL ~7 milliards $.", relatedTerms: ["optimistic-rollup", "layer-2", "base"] },
  { term: "Base", slug: "base", category: "Layer 2", definition: "L2 Ethereum lancée par Coinbase en 2023, basée sur le OP Stack. Croissance fulgurante (TVL ~10 milliards $ fin 2024) grâce à l'intégration native dans Coinbase. Hub des memecoins et social tokens (Friend.tech). Pas de token natif — fees payés en ETH.", relatedTerms: ["optimism", "layer-2", "coinbase"] },
  { term: "Polygon", slug: "polygon", category: "Layer 2", definition: "Initialement « Matic Network » (sidechain Ethereum), Polygon est devenu un écosystème de scaling : Polygon PoS (sidechain), Polygon zkEVM (ZK-Rollup), Polygon CDK (kit pour lancer sa propre chain). Token MATIC en cours de migration vers POL. Adoption institutionnelle (Stripe, Adidas, Reddit).", relatedTerms: ["layer-2", "ethereum", "zk-rollup"] },
  { term: "zkSync", slug: "zksync", category: "Layer 2", definition: "ZK-Rollup pionnier sur Ethereum, lancé par Matter Labs. Compatible EVM. Token ZK lancé en 2024 via airdrop. Hyperchains : framework pour lancer ses propres ZK-chains. TVL en croissance régulière.", relatedTerms: ["zk-rollup", "layer-2", "linea"] },
  { term: "Linea", slug: "linea", category: "Layer 2", definition: "ZK-Rollup développé par Consensys (Metamask). Lancé en 2023. Compatible EVM. Adoption rapide grâce à l'intégration Metamask et aux campagnes d'incentive. Pas encore de token natif (anticipation airdrop massif). TVL ~1 milliard $.", relatedTerms: ["zk-rollup", "layer-2", "metamask"] },
  { term: "Starknet", slug: "starknet", category: "Layer 2", definition: "ZK-Rollup utilisant le langage Cairo (non-EVM). Approche différenciée mais courbe d'apprentissage abrupte pour les devs. Token STRK lancé en 2024. Écosystème jeune mais innovations techniques fortes (account abstraction natif, paymaster).", relatedTerms: ["zk-rollup", "layer-2"] },
  { term: "Solana", slug: "solana", category: "Layer 2", definition: "Layer 1 ultra-performante (>3 000 TPS pratiques), basée sur Proof of History + Proof of Stake. Frais quasi nuls (< 0,001 $). Écosystème explosif en 2024-2025 : memecoins (BONK, WIF), DeFi (Jupiter, Drift), NFT (Magic Eden). Critiquée pour ses outages historiques mais stabilité grandement améliorée.", relatedTerms: ["layer-1", "phantom"] },
  { term: "Avalanche", slug: "avalanche", category: "Layer 2", definition: "Layer 1 EVM-compatible avec architecture multi-chain : C-Chain (smart contracts), P-Chain (validators), X-Chain (assets). Subnets : sous-réseaux personnalisables, modèle phare. Adoption institutionnelle (DeFi, gaming, RWA). Token AVAX.", relatedTerms: ["layer-1", "subnet"] },
  { term: "Cosmos", slug: "cosmos", category: "Layer 2", definition: "« Internet des blockchains » : framework pour créer des blockchains souveraines interopérables via le protocole IBC. Chaque chain est indépendante mais peut échanger tokens et données avec les autres. Hub : Cosmos Hub (token ATOM). Écosystème : Osmosis, Celestia, Injective, dYdX v4.", relatedTerms: ["polkadot", "layer-1"] },
  { term: "Polkadot", slug: "polkadot", category: "Layer 2", definition: "Layer 0 conçue par Gavin Wood (co-fondateur Ethereum). Architecture : Relay Chain (sécurité commune) + parachains (blockchains spécialisées) + bridges. Token DOT pour staking et auctions de parachains. Concurrent direct de Cosmos sur le créneau interopérabilité.", relatedTerms: ["cosmos", "layer-1"] },
  { term: "Bridge", slug: "bridge", category: "DeFi", definition: "Protocole permettant de déplacer des tokens d'une blockchain à une autre. Modèles : lock-and-mint (le token est verrouillé sur la chain A et minté sur la B), liquidity-based (pool des deux côtés). Premier vecteur de hack en crypto : bridges victimes de 2,5 milliards $ en 2022 (Ronin, Wormhole, Nomad). À utiliser avec prudence.", relatedTerms: ["wrapped-token", "exploit"] },
  { term: "Wrapped token", slug: "wrapped-token", category: "DeFi", definition: "Représentation d'un token natif (BTC, ETH) sur une autre blockchain via un bridge. Exemple : WBTC = Bitcoin wrappé sur Ethereum, 1:1, custodial (BitGo). Permet d'utiliser BTC dans la DeFi Ethereum. Risque : faillite ou hack du custodian. Variantes décentralisées : tBTC (Threshold), renBTC (deprecated).", relatedTerms: ["bridge", "defi"] },
  // ----- Régulation France / EU -----
  { term: "MiCA", slug: "mica", category: "Régulation", definition: "Markets in Crypto-Assets. Règlement européen unifié sur les crypto-actifs, applicable depuis juin 2024 pour les stablecoins et fin 2024 pour les CASP. Impose un agrément européen unique aux plateformes crypto, des règles de transparence pour les émetteurs et des protections renforcées pour les utilisateurs. Game-changer pour la conformité européenne.", relatedTerms: ["casp", "psan", "stablecoin"], internalLink: "/outils/verificateur-mica" },
  { term: "PSAN", slug: "psan", category: "Régulation", definition: "Prestataire de Services sur Actifs Numériques. Statut français issu de la loi PACTE (2019) qui s'applique aux acteurs crypto (exchanges, wallets, conseils). Enregistrement obligatoire auprès de l'AMF, contrôle ACPR. Devient progressivement obsolète avec la transition vers le statut CASP européen (MiCA) d'ici juillet 2026.", relatedTerms: ["amf", "casp", "mica"] },
  { term: "CASP", slug: "casp", category: "Régulation", definition: "Crypto-Asset Service Provider. Statut européen MiCA équivalent du PSAN français mais valable dans toute l'UE. Impose des exigences de capital, gouvernance, sécurité, lutte anti-blanchiment. Les PSAN français doivent migrer vers CASP avant juillet 2026 sous peine d'interdiction d'exercice.", relatedTerms: ["mica", "psan", "amf"] },
  { term: "AMF", slug: "amf", category: "Régulation", definition: "Autorité des Marchés Financiers. Régulateur français de la finance, supervise les PSAN, valide les whitepapers ICO, sanctionne les arnaques crypto, publie la liste noire des plateformes non autorisées (consultez systématiquement avant de déposer des fonds). Site : amf-france.org.", relatedTerms: ["psan", "acpr", "tracfin"] },
  { term: "ACPR", slug: "acpr", category: "Régulation", definition: "Autorité de Contrôle Prudentiel et de Résolution. Régulateur bancaire français adossé à la Banque de France. Co-supervise les PSAN avec l'AMF, notamment sur les aspects LCB-FT (lutte contre blanchiment et financement du terrorisme). Décerne les agréments PSAN les plus exigeants (ex : Bitstack, Coinhouse).", relatedTerms: ["amf", "psan", "tracfin"] },
  { term: "Tracfin", slug: "tracfin", category: "Régulation", definition: "Service français de renseignement financier rattaché à Bercy. Reçoit les déclarations de soupçon des PSAN et autres acteurs financiers. Toute transaction crypto > 1000 € peut faire l'objet d'une vérification. Coopère avec les services équivalents européens et internationaux (FATF).", relatedTerms: ["acpr", "lcbft", "kyc"] },
  { term: "KYC", slug: "kyc", category: "Régulation", definition: "Know Your Customer. Procédure d'identification obligatoire chez tout PSAN/CASP : pièce d'identité, justificatif de domicile, parfois selfie. Imposée par la lutte anti-blanchiment (LCB-FT). Permet à la plateforme de transmettre des informations à Tracfin et à l'administration fiscale. Sans KYC = transactions limitées (€2k/mois max chez la plupart).", relatedTerms: ["aml", "lcbft", "tracfin"] },
  { term: "AML", slug: "aml", category: "Régulation", definition: "Anti-Money Laundering. Réglementation visant à prévenir le blanchiment d'argent. Impose KYC, surveillance des transactions atypiques, déclaration de soupçon, conservation des données pendant 5 ans. Standards européens (5e et 6e directives AMLD), normes mondiales FATF/GAFI. Toute crypto qui ignore l'AML s'expose à des sanctions.", relatedTerms: ["kyc", "lcbft", "tracfin"] },
  { term: "LCB-FT", slug: "lcbft", category: "Régulation", definition: "Lutte contre le Blanchiment de Capitaux et le Financement du Terrorisme. Cadre légal français qui transpose les directives AML européennes. Impose aux PSAN/banques/notaires de déclarer toute opération suspecte à Tracfin. Encadré par le Code monétaire et financier. Contrôles ACPR aléatoires et fréquents.", relatedTerms: ["aml", "kyc", "tracfin"] },
  { term: "PFU", slug: "pfu", category: "Régulation", definition: "Prélèvement Forfaitaire Unique. Régime fiscal français applicable par défaut aux plus-values crypto des particuliers : 30 % flat (12,8 % IR + 17,2 % prélèvements sociaux). S'applique au-delà du seuil d'exonération de 305 € de cessions annuelles. Alternative : barème progressif si TMI < 12,8 %.", relatedTerms: ["fiscalite", "cerfa-2086"], internalLink: "/outils/calculateur-fiscalite" },
  { term: "Cerfa 2086", slug: "cerfa-2086", category: "Régulation", definition: "Formulaire fiscal français pour déclarer les plus-values issues de cessions de crypto-actifs. Obligatoire dès que le total des cessions dépasse 305 € sur l'année. À joindre à la déclaration 2042. Calcule la plus-value globale par méthode du prix moyen pondéré d'acquisition (PMPA).", relatedTerms: ["pfu", "fiscalite"], internalLink: "/outils/calculateur-fiscalite" },
  { term: "Travel Rule", slug: "travel-rule", category: "Régulation", definition: "Règle FATF imposant aux PSAN/CASP de transmettre l'identité de l'expéditeur et du destinataire pour toute transaction crypto > 1000 €. Effective dans l'UE depuis fin 2024. Impacte fortement les retraits vers wallets externes : KYC double désormais souvent demandé. Critiquée pour son atteinte à la pseudonymité.", relatedTerms: ["aml", "kyc", "mica"] },
  { term: "FATF", slug: "fatf", category: "Régulation", definition: "Financial Action Task Force (GAFI en français). Organisme intergouvernemental qui édicte les standards mondiaux de lutte anti-blanchiment. Ses recommandations sont transposées en droit national. La Travel Rule en est une émanation. Influence majeure sur la régulation crypto mondiale.", relatedTerms: ["aml", "travel-rule"] },
  // ----- Tokenomics & ICO -----
  { term: "Tokenomics", slug: "tokenomics", category: "Tokenomics", definition: "Modèle économique d'un token : supply totale, distribution initiale (équipe, investisseurs, communauté, trésorerie), schedule d'émission (inflation/déflation), mécanismes de burn et utilité. Une bonne tokenomics aligne les incitations sur le long terme. Une mauvaise = pump-and-dump garanti. Toujours analyser avant d'investir.", relatedTerms: ["whitepaper", "supply", "vesting"] },
  { term: "Supply", slug: "supply", category: "Tokenomics", definition: "Quantité totale de tokens d'une cryptomonnaie. Trois mesures : circulating supply (en circulation), total supply (créés moins burnés), max supply (plafond absolu). Bitcoin : max supply 21 M. Ethereum : pas de max supply, mais émission proche de zéro post-Merge (parfois déflationniste avec EIP-1559).", relatedTerms: ["tokenomics", "halving"] },
  { term: "Burn", slug: "burn", category: "Tokenomics", definition: "Destruction définitive de tokens en les envoyant à une adresse inaccessible (sans clé privée). Réduit la supply et crée une pression déflationniste. Exemples : Ethereum brûle une partie des frais de transaction (EIP-1559) ; Binance burn trimestriel de BNB. Indicateur de tokenomics saine.", relatedTerms: ["tokenomics", "supply"] },
  { term: "Vesting", slug: "vesting", category: "Tokenomics", definition: "Période de blocage des tokens distribués à l'équipe, aux investisseurs early ou aux conseillers. Empêche le dump immédiat post-listing. Schedule typique : cliff de 6-12 mois puis linéaire sur 24-48 mois. Vérifier le vesting est crucial : un déblocage massif crée souvent un crash. Suivi : Token Unlocks.", relatedTerms: ["tokenomics", "supply"] },
  { term: "Cliff", slug: "cliff", category: "Tokenomics", definition: "Période initiale durant laquelle aucun token vested ne peut être réclamé. Exemple : cliff 12 mois + vesting linéaire 36 mois. À la fin du cliff, déblocage rétroactif des 12 premiers mois en une fois. Mécanisme pour aligner long terme l'équipe avec le projet.", relatedTerms: ["vesting", "tokenomics"] },
  { term: "ICO", slug: "ico", category: "Tokenomics", definition: "Initial Coin Offering. Levée de fonds en crypto où un projet vend ses tokens contre BTC/ETH. Boom historique en 2017 (Ethereum, EOS, Tezos). Régulation depuis : la majorité des ICOs ont été qualifiées de securities non-enregistrées par la SEC. Format remplacé par IDO, IEO, Launchpads.", relatedTerms: ["ido", "ieo", "launchpad"] },
  { term: "IDO", slug: "ido", category: "Tokenomics", definition: "Initial DEX Offering. Lancement d'un token directement via un DEX (souvent Uniswap, PancakeSwap, Camelot). Permet une liquidité immédiate. Risque : sniper bots, manipulation du prix initial. Variantes : LBP (Liquidity Bootstrapping Pool, Balancer) avec courbe de prix décroissante.", relatedTerms: ["ico", "ieo", "dex"] },
  { term: "IEO", slug: "ieo", category: "Tokenomics", definition: "Initial Exchange Offering. Lancement d'un token via une plateforme centralisée (Binance Launchpad, OKX Jumpstart). La plateforme effectue un due diligence et garantit la liquidité au listing. Plus rassurant qu'un IDO mais cher pour le projet. Allocation souvent réservée aux holders du token de la plateforme.", relatedTerms: ["ico", "ido", "launchpad"] },
  { term: "Launchpad", slug: "launchpad", category: "Tokenomics", definition: "Plateforme qui héberge des IDO/IEO et permet aux investisseurs de participer à des ventes privées. Exemples : Binance Launchpad, CoinList, DAO Maker, Polkastarter. Souvent : sélection des projets, KYC, allocation tier-based. Apporte du legitimacy aux projets early-stage.", relatedTerms: ["ico", "ido", "ieo"] },
  { term: "Airdrop", slug: "airdrop", category: "Tokenomics", definition: "Distribution gratuite de tokens à une communauté ciblée (early users, holders d'un autre token, participants à une testnet). Stratégie marketing virale et alternative au listing payant. Airdrops historiques majeurs : Uniswap (UNI, 400 tokens = 1200 $ en 2020), Arbitrum, Optimism, Jito (Solana). À chasser activement.", relatedTerms: ["tokenomics"] },
  { term: "Pre-sale", slug: "pre-sale", category: "Tokenomics", definition: "Vente privée de tokens à des investisseurs early (VCs, angel investors, communauté core) avant le listing public. Prix généralement très bas avec vesting long. Pour les retails, accès souvent via launchpads ou whitelist. Gros risque/gros reward — à manier avec prudence.", relatedTerms: ["ico", "ido", "vesting"] },
  { term: "Marketcap", slug: "marketcap", category: "Trading", definition: "Capitalisation boursière d'une cryptomonnaie : prix unitaire × supply en circulation. Indicateur de taille. Bitcoin > 1 trillion $ ; Ethereum > 400 milliards $. À comparer avec FDV (Fully Diluted Valuation) qui inclut les tokens non-débloqués. Une supply faible peut faussement gonfler le marketcap initial.", relatedTerms: ["fdv", "supply"] },
  { term: "FDV", slug: "fdv", category: "Trading", definition: "Fully Diluted Valuation. Capitalisation théorique si tous les tokens (vested ou non) étaient en circulation. Calcul : prix × max supply. Toujours comparer marketcap vs FDV : un FDV très supérieur au marketcap signale qu'une grande partie de la supply va être débloquée — pression baissière à venir.", relatedTerms: ["marketcap", "supply", "vesting"] },
  { term: "Volume 24h", slug: "volume-24h", category: "Trading", definition: "Total des transactions en valeur sur une crypto durant les 24 dernières heures. Indicateur de liquidité et d'intérêt. Un volume très élevé sur un microcap = signal de pump-and-dump probable. Ratio volume/marketcap idéal : 5-15 % pour les top 100 cryptos. À cross-checker avec CoinGecko + DexScreener.", relatedTerms: ["liquidity", "marketcap"] },
  { term: "TVL", slug: "tvl", category: "DeFi", definition: "Total Value Locked. Valeur totale des actifs déposés dans un protocole DeFi (lending, AMM, staking). Indicateur clé de santé et d'adoption. TVL global DeFi : ~80 milliards $ fin 2024. Suivi via DefiLlama. Attention : TVL peut être inflaté par les mêmes actifs comptés plusieurs fois (recyclage cross-protocoles).", relatedTerms: ["defi", "liquidity-pool"] },
  { term: "APR", slug: "apr", category: "DeFi", definition: "Annual Percentage Rate. Taux de rendement annuel sans intérêts composés. Si vous stake 1000 $ à 10 % APR, vous touchez 100 $ après un an. Plus simple à calculer que l'APY. Souvent utilisé par les protocoles de lending pour les emprunts.", relatedTerms: ["apy", "yield"] },
  { term: "APY", slug: "apy", category: "DeFi", definition: "Annual Percentage Yield. Rendement annualisé avec intérêts composés (réinvestissement automatique). Toujours supérieur à l'APR à taux égal. Si APR = 10 %, APY ≈ 10,47 % (composé quotidiennement). Métrique standard dans les pools de yield farming. Méfiance : un APY de 1000 % = subvention en token qui finira à 0.", relatedTerms: ["apr", "yield-farming"] },
  { term: "Yield", slug: "yield", category: "DeFi", definition: "Rendement passif généré par une crypto déposée dans un protocole : intérêts de lending, fees AMM, récompenses de staking. Le « real yield » exclut l'inflation du token de récompense. Exemple : un yield de 50 % en token X qui se déprécie de 70 % = perte. Toujours analyser en USD effectif.", relatedTerms: ["apr", "apy", "real-yield"] },
  { term: "Real yield", slug: "real-yield", category: "DeFi", definition: "Rendement DeFi distribué en stablecoins ou tokens majeurs (ETH, BTC), généré par les frais réels du protocole — pas par l'émission inflationniste de tokens. Marqueur de protocole sain et durable. Exemples : GMX, Gains Network, Pendle. À privilégier vs les yield artificiels en farm token.", relatedTerms: ["yield", "apy"] },
  { term: "Governance token", slug: "governance-token", category: "Tokenomics", definition: "Token qui confère un droit de vote sur les décisions d'un protocole DeFi (modifs de paramètres, allocation de la trésorerie, listings). Exemples : UNI (Uniswap), AAVE, COMP, CRV. Souvent peu de utilité économique au-delà du vote — d'où la critique « token gouvernance = ticket sans valeur ». Beaucoup ajoutent fee-sharing pour rectifier.", relatedTerms: ["dao", "vote-escrow"] },
  { term: "DAO", slug: "dao", category: "Tokenomics", definition: "Decentralized Autonomous Organization. Organisation gouvernée on-chain par les détenteurs d'un token de gouvernance, sans hiérarchie traditionnelle. Décisions prises par vote (Snapshot, Tally). Exemples : Uniswap DAO, MakerDAO, Aave DAO. Permet de gérer collectivement des trésoreries de plusieurs centaines de millions $.", relatedTerms: ["governance-token", "smart-contract"] },
  { term: "Vote-escrow", slug: "vote-escrow", category: "Tokenomics", definition: "Mécanisme inventé par Curve : verrouiller des tokens (CRV) pour une durée (jusqu'à 4 ans) en échange d'un vote-escrowed token (veCRV) avec pouvoir de vote et droit aux fees. Plus on lock long, plus on a de poids. Adopté par Convex, Frax, Balancer. Aligné incitations long terme.", relatedTerms: ["governance-token", "curve"] },
  // ----- Smart contracts & dev -----
  { term: "Smart contract", slug: "smart-contract", category: "DeFi", definition: "Programme informatique exécuté sur une blockchain, qui s'exécute automatiquement quand certaines conditions sont remplies. Inventé par Ethereum (langage Solidity). Base de toute la DeFi, des NFT, des DAO. Immutable une fois déployé : un bug = perte permanente possible (cf. The DAO hack, 2016). Audits indispensables.", relatedTerms: ["solidity", "evm", "audit"] },
  { term: "Solidity", slug: "solidity", category: "DeFi", definition: "Langage de programmation principal pour écrire des smart contracts sur Ethereum et chaînes EVM. Syntaxe inspirée de JavaScript et C++. Compilé en bytecode EVM. Écosystème mature : OpenZeppelin pour les standards, Foundry/Hardhat pour les frameworks. Apprentissage indispensable pour devenir dev Web3.", relatedTerms: ["smart-contract", "evm"] },
  { term: "EVM", slug: "evm", category: "Layer 2", definition: "Ethereum Virtual Machine. Machine virtuelle qui exécute les smart contracts Ethereum, dupliquée sur tous les nœuds. Standard de facto : la plupart des Layer 2 et chains alternatives sont « EVM-compatible » pour faciliter la portabilité des contrats (Polygon, BNB Chain, Avalanche C-Chain, Arbitrum).", relatedTerms: ["smart-contract", "ethereum"] },
  { term: "Audit", slug: "audit", category: "Sécurité", definition: "Revue de code d'un smart contract par une firme spécialisée (Trail of Bits, OpenZeppelin, ConsenSys Diligence, CertiK) pour identifier vulnérabilités et bugs. Coût : 30k-300k $ selon la complexité. Indispensable avant tout déploiement gérant > 1 M$. Un audit n'élimine pas le risque mais le réduit fortement.", relatedTerms: ["smart-contract", "exploit"] },
  { term: "Exploit", slug: "exploit", category: "Sécurité", definition: "Attaque utilisant une vulnérabilité d'un smart contract pour vider les fonds. 2022 a vu des exploits majeurs : Wormhole (320 M$), Ronin (625 M$), Nomad (190 M$). Vecteurs typiques : reentrancy, oracle manipulation, flash loan, signature replay, accès non-autorisé. Suivi : rekt.news.", relatedTerms: ["audit", "smart-contract", "flash-loan"] },
  { term: "Reentrancy", slug: "reentrancy", category: "Sécurité", definition: "Vulnérabilité classique des smart contracts : un contrat externe rappelle (« re-enter ») le contrat victime avant que celui-ci n'ait mis à jour son état, vidant les fonds en boucle. Exploitée dans The DAO hack (2016, 60 M$). Solution : pattern checks-effects-interactions, ReentrancyGuard d'OpenZeppelin.", relatedTerms: ["exploit", "smart-contract"] },
  { term: "Oracle", slug: "oracle", category: "DeFi", definition: "Service qui amène des données off-chain (prix, météo, résultats sportifs) vers les smart contracts. Sans oracle, la DeFi ne pourrait pas fonctionner (pas de prix BTC/USD on-chain natif). Leader : Chainlink. Risque clé : manipulation d'oracle (vol via flash loan + pump prix sur DEX). Préférer les oracles décentralisés.", relatedTerms: ["chainlink", "smart-contract"] },
  { term: "Chainlink", slug: "chainlink", category: "DeFi", definition: "Réseau d'oracles décentralisé leader, sécurise > 17 trillions $ de TVS (Total Value Secured). Fournit price feeds, VRF (random verifiable), CCIP (cross-chain). Utilisé par Aave, Synthetix, Compound. Token LINK pour payer les opérateurs de nœuds. Pilier infrastructure de la DeFi.", relatedTerms: ["oracle", "defi"] },
  { term: "Dapp", slug: "dapp", category: "DeFi", definition: "Decentralized Application. Application qui interagit avec des smart contracts plutôt qu'un backend traditionnel. Exemples : Uniswap, OpenSea, Aave. Frontend classique (React) + connection wallet (Metamask) + appels smart contracts via ethers.js/viem. Pas de serveur central de données.", relatedTerms: ["smart-contract", "metamask"] },
  { term: "Web3", slug: "web3", category: "DeFi", definition: "Vision d'un web décentralisé basé sur les blockchains : utilisateurs propriétaires de leurs données, identités souveraines (wallets), valeurs natives (cryptos). S'oppose au Web2 dominé par les GAFAM. Inclut DeFi, NFT, DAO, gaming on-chain, social tokens. Maturation lente mais réelle adoption.", relatedTerms: ["dapp", "defi", "nft"] },
  { term: "Account abstraction", slug: "account-abstraction", category: "Wallet", definition: "Innovation EIP-4337 sur Ethereum : remplace les wallets EOA classiques par des smart contracts wallets, permettant batching, gas sponsorship, social recovery, multi-signature, sessions keys. Améliore drastiquement l'UX. Adoption croissante (Argent, Safe, Biconomy). Future norme prévisible.", relatedTerms: ["wallet", "smart-contract"] },
  { term: "Gas sponsorship", slug: "gas-sponsorship", category: "Wallet", definition: "Mécanisme permettant à un tiers (l'app, un sponsor) de payer le gas pour l'utilisateur. Possible grâce à l'account abstraction et aux paymasters ERC-4337. Cas d'usage : onboarding sans crypto, gaming free-to-play, airdrops. Game-changer UX pour le mass adoption.", relatedTerms: ["account-abstraction", "gas-fees"] },
  // ----- Trading avancé -----
  { term: "Order limit", slug: "order-limit", category: "Trading", definition: "Ordre d'achat ou de vente à un prix précis. Ne s'exécute que si le marché atteint le prix indiqué. Maker order : ajoute de la liquidité au carnet. Frais réduits (souvent 0,02-0,1 %). Stratégie de patience pour acheter au support / vendre à la résistance.", relatedTerms: ["order-market", "stop-loss"] },
  { term: "Order market", slug: "order-market", category: "Trading", definition: "Ordre d'achat ou de vente exécuté immédiatement au meilleur prix disponible. Taker order : retire de la liquidité du carnet. Frais plus élevés (~0,1-0,2 %). Risque : slippage en cas de carnet peu profond ou de marché volatile.", relatedTerms: ["order-limit", "slippage"] },
  { term: "Stop-loss", slug: "stop-loss", category: "Trading", definition: "Ordre de vente automatique déclenché si le prix tombe sous un seuil défini. Limite les pertes. Discipline indispensable du trader pro : « cut your losses, let your winners run ». Risque : être stop-out par une mèche violente puis voir le prix rebondir. Stop-loss trailing : suit le cours à la hausse.", relatedTerms: ["take-profit", "order-limit"] },
  { term: "Take-profit", slug: "take-profit", category: "Trading", definition: "Ordre de vente automatique déclenché à un seuil de gain défini. Sécurise les profits sans surveiller en permanence. Stratégie courante : prendre 50 % à la première résistance, laisser courir le reste avec un trailing stop. Évite l'erreur classique de « ne pas vendre quand le prix monte ».", relatedTerms: ["stop-loss", "order-limit"] },
  { term: "Support", slug: "support", category: "Trading", definition: "Niveau de prix auquel la demande est suffisamment forte pour empêcher la chute. En analyse technique, ligne horizontale tracée sur les bas significatifs. Si le support tient = rebond probable. S'il casse = nouveau drawdown. Plus le support est testé, plus il est fort... jusqu'à ce qu'il casse.", relatedTerms: ["resistance", "trend"] },
  { term: "Resistance", slug: "resistance", category: "Trading", definition: "Niveau de prix auquel l'offre est suffisamment forte pour empêcher la hausse. Symétrique du support. Casser une résistance = signal d'achat. Une résistance cassée devient souvent un support (« polarité »). Premier niveau à viser pour un take-profit.", relatedTerms: ["support", "trend"] },
  { term: "Breakout", slug: "breakout", category: "Trading", definition: "Cassure d'un niveau technique majeur (résistance, ligne de tendance, range). Souvent accompagnée d'une explosion de volume. Stratégie : acheter le breakout et placer un stop-loss sous le niveau cassé. Risque : faux breakout (« fakeout ») où le prix revient sous le niveau, piégeant les longs.", relatedTerms: ["resistance", "support"] },
  { term: "Trend", slug: "trend", category: "Trading", definition: "Direction générale du prix sur une période. Uptrend : sommets et creux ascendants. Downtrend : sommets et creux descendants. Range : pas de tendance, prix oscille entre support et résistance. Citation : « The trend is your friend until it ends ». Indicateurs : moyennes mobiles, ADX.", relatedTerms: ["support", "resistance"] },
  { term: "RSI", slug: "rsi", category: "Trading", definition: "Relative Strength Index. Indicateur d'analyse technique mesurant la force d'une tendance sur une échelle 0-100. RSI > 70 = sur-acheté (correction probable). RSI < 30 = sur-vendu (rebond probable). Divergences RSI / prix = signal puissant. Période standard : 14 bougies. Inventé par J. Welles Wilder.", relatedTerms: ["macd", "trend"] },
  { term: "MACD", slug: "macd", category: "Trading", definition: "Moving Average Convergence Divergence. Indicateur basé sur deux moyennes mobiles exponentielles (12 et 26 périodes). Croisement haussier de la ligne MACD au-dessus de sa signal = signal d'achat. Histogramme MACD = momentum. Combiner avec RSI et volume pour confirmation.", relatedTerms: ["rsi", "trend"] },
  { term: "Moyenne mobile", slug: "moyenne-mobile", category: "Trading", definition: "Indicateur lissant le prix sur N périodes. SMA (simple) ou EMA (exponentielle, plus réactive). Moyennes clés : 20 (court terme), 50 (moyen), 200 (long terme). Crossing 50/200 (Golden Cross / Death Cross) signaux historiques. Le prix au-dessus de la 200 = bull ; en-dessous = bear.", relatedTerms: ["trend", "macd"] },
  { term: "Bollinger Bands", slug: "bollinger-bands", category: "Trading", definition: "Indicateur de volatilité : moyenne mobile ± 2 écarts-types. Quand les bandes se resserrent (« squeeze »), une explosion de volatilité est imminente. Prix touchant la bande supérieure = sur-acheté local. Inférieure = sur-vendu. Inventé par John Bollinger.", relatedTerms: ["volatilite", "trend"] },
  { term: "Fibonacci", slug: "fibonacci", category: "Trading", definition: "Outil d'analyse technique basé sur les ratios de la suite de Fibonacci (23,6 % - 38,2 % - 50 % - 61,8 % - 78,6 %). Tracé entre un swing low et un swing high pour identifier des zones probables de retracement ou d'extension. Très utilisé par les traders crypto pour positionner stop-loss et take-profit.", relatedTerms: ["support", "resistance"] },
  { term: "Volatilité", slug: "volatilite", category: "Trading", definition: "Amplitude des variations de prix. Crypto = ultra-volatile : Bitcoin a +/- 5 % par jour en moyenne, Ethereum +/- 7 %, microcaps +/- 30 %. Mesurée par l'écart-type des rendements. Volatilité élevée = opportunités mais aussi liquidations. Ne jamais entrer en levier sans comprendre la volatilité de l'asset.", relatedTerms: ["bollinger-bands", "leverage"] },
  // ----- Plus de termes essentiels -----
  { term: "Whale", slug: "whale", category: "Trading", definition: "Investisseur détenant une quantité massive d'une crypto, capable d'influencer son prix. Sur Bitcoin : > 1000 BTC. Sur altcoins : > 1 % de la supply. Suivre les whales (whale alerts, etherscan, dune analytics) donne des signaux précieux. Méfiance : certaines whales coordonnent des pump-and-dump.", relatedTerms: ["bitcoin", "fud"] },
  { term: "Bagholder", slug: "bagholder", category: "Trading", definition: "Investisseur qui détient un token ayant chuté drastiquement et qui n'arrive pas à s'en défaire. Souvent associé aux memecoins ou ICO 2017-2018. Comportement émotionnel : refus d'accepter la perte, espoir d'un rebond miraculeux. Antidote : stop-loss prédéfinis et journal de trading.", relatedTerms: ["fomo", "shitcoin"] },
  { term: "Dust", slug: "dust", category: "Wallet", definition: "Très petites quantités de crypto (souvent < 1 $) restant dans un wallet après des transactions. Inutilisables car les frais dépassent leur valeur. La plupart des CEX permettent de convertir tous les dusts en BNB/USDT. En DeFi, on peut les vendre via des aggregateurs (1inch, Bungee).", relatedTerms: ["wallet"] },
  { term: "Dust attack", slug: "dust-attack", category: "Sécurité", definition: "Envoi de poussières (« dust ») de crypto à de nombreux wallets pour les tracker. En analysant les transactions ultérieures, l'attaquant peut désanonymiser les utilisateurs et lier des adresses entre elles. Protection : ne jamais consolider des dusts inconnus, utiliser un wallet séparé.", relatedTerms: ["dust", "phishing"] },
  { term: "Faucet", slug: "faucet", category: "Tokenomics", definition: "Site distribuant gratuitement de petites quantités de crypto (généralement sur testnet). Permet aux développeurs de tester des dApps sans dépenser de vrais fonds. Faucets mainnet historiques (Bitcoin Faucet 2010 distribuant 5 BTC) — désormais quasi disparus. Outil indispensable pour devs Web3.", relatedTerms: ["testnet"] },
  { term: "Testnet", slug: "testnet", category: "Tokenomics", definition: "Réseau de test parallèle au mainnet, utilisant des tokens sans valeur. Permet aux devs de tester les smart contracts en conditions réelles. Exemples : Sepolia (Ethereum), Goerli (deprecated), Devnet (Solana). Participer activement aux testnet = chance d'airdrop majeur (cf. Arbitrum, Optimism).", relatedTerms: ["mainnet", "faucet", "airdrop"] },
  { term: "Mainnet", slug: "mainnet", category: "Tokenomics", definition: "Réseau principal d'une blockchain, où circulent les tokens à valeur réelle. S'oppose au testnet. « Mainnet launch » = moment où un projet passe de la preuve de concept à la production. Étape critique : pression maximale, audit indispensable.", relatedTerms: ["testnet"] },
  { term: "Hot start", slug: "hot-start", category: "Trading", definition: "Lancement d'un token avec une marketcap initiale élevée et liquidité importante, généralement via un IDO réussi. Inverse du « stealth launch ». Avantages : volatilité moindre au début, attire l'attention. Inconvénient : moins de potentiel d'upside x100.", relatedTerms: ["ido", "launchpad"] },
  { term: "Stealth launch", slug: "stealth-launch", category: "Trading", definition: "Lancement d'un token sans annonce préalable, souvent sur DEX. Stratégie pour éviter les bots de sniping et donner une chance équitable aux early buyers. Très commun pour les memecoins Solana. Risque : facilite les rugpulls (l'équipe disparaît avec la liquidité).", relatedTerms: ["rugpull", "memecoin"] },
  { term: "Front-running bot", slug: "front-running-bot", category: "DeFi", definition: "Bot automatisé qui scrute la mempool pour identifier des transactions juteuses et soumettre les siennes avant, profitant du MEV. Activité industrielle générant des centaines de M$/an. Anti-MEV : Flashbots Protect, transactions privées, RPC anti-MEV.", relatedTerms: ["mev", "frontrunning", "mempool"] },
  { term: "Snipe bot", slug: "snipe-bot", category: "Trading", definition: "Bot qui achète massivement un token dès la création de sa pool de liquidité, avant que les humains aient le temps de réagir. Permet d'acheter au prix initial puis de dump après un pump. Quasi-impossible à concurrencer sans bot soi-même. Justifie les présales et whitelists.", relatedTerms: ["frontrunning", "memecoin"] },
  { term: "Trading bot", slug: "trading-bot", category: "Trading", definition: "Logiciel qui exécute automatiquement des stratégies de trading selon des règles définies (RSI, breakout, grid). Plateformes : 3Commas, Cryptohopper, Bitsgap. Statistiquement, > 95 % des bots retail perdent de l'argent. Préférer un DCA programmé manuel.", relatedTerms: ["dca", "trend"] },
  { term: "Arbitrage", slug: "arbitrage", category: "Trading", definition: "Profiter de l'écart de prix d'un même asset entre deux marchés. Exemple : BTC à 100 000 $ sur Binance vs 100 200 $ sur Coinbase = arbitrage de 0,2 %. Sur DEX : arbitrage cross-chain via bridges. Pro game : exécuté par bots à microsecondes. Pour retail, marge presque toujours mangée par les frais.", relatedTerms: ["spread", "mev"] },
  { term: "Whitelist", slug: "whitelist", category: "Tokenomics", definition: "Liste d'adresses pré-approuvées pour participer à un événement (mint NFT, présale, airdrop). Souvent obtenue via gains de communauté (Twitter, Discord, OG roles). Permet à l'équipe de récompenser ses early supporters. Ouverte généralement plusieurs heures avant le public mint.", relatedTerms: ["airdrop", "presale", "nft"] },
  { term: "OG", slug: "og", category: "Tokenomics", definition: "Original Gangster. Surnom donné aux membres pionniers d'une communauté crypto, souvent récompensés par des NFT exclusifs, allocations whitelist, ou rôles Discord prestigieux. Statut respecté dans l'écosystème. Devenu OG d'un projet = avoir prouvé sa loyauté avant le hype.", relatedTerms: ["whitelist", "nft"] },
  { term: "WAGMI", slug: "wagmi", category: "Trading", definition: "We're All Gonna Make It. Slogan optimiste de la communauté crypto, exprimant la confiance dans un futur prospère pour ceux qui restent investis. Antithèse : NGMI (Not Gonna Make It). Devenu meme et culture, mais à manier avec recul : la majorité des memecoins NGMI.", relatedTerms: ["hodl", "fomo"] },
  { term: "Diamond hands", slug: "diamond-hands", category: "Trading", definition: "Investisseur qui ne vend jamais malgré la volatilité, considéré comme « solide comme un diamant ». Inverse : paper hands (vend à la première baisse). Culture forte sur Reddit (WSB) et Twitter crypto. Stratégie efficace en bull market, dangereuse sur shitcoins.", relatedTerms: ["hodl", "fomo"] },
  { term: "GMI", slug: "gmi", category: "Trading", definition: "Gonna Make It. Variante de WAGMI, focus individuel : « tu vas réussir grâce à tes choix actuels ». Souvent dit en encouragement à un nouvel investisseur ou à un projet qui démarre bien.", relatedTerms: ["wagmi"] },
  { term: "Degen", slug: "degen", category: "Trading", definition: "Degenerate. Investisseur prenant des risques extrêmes (microcaps, leverage 50x, memecoins fraîchement lancés). Culture revendiquée sur Crypto Twitter. Peut générer des x100 ou ruiner totalement. À distinguer du serious investor qui fait du DCA Bitcoin.", relatedTerms: ["memecoin", "leverage", "shitcoin"] },
  { term: "Smart money", slug: "smart-money", category: "Trading", definition: "Capitaux investis par des acteurs informés et expérimentés (VCs, hedge funds crypto, whales analytiques). Suivre la smart money = stratégie validée. Outils : Nansen, Arkham, Lookonchain. Décisions souvent à contre-courant du retail.", relatedTerms: ["whale"] },
  { term: "Retail", slug: "retail", category: "Trading", definition: "Investisseurs particuliers, par opposition aux institutionnels et aux whales. Souvent dernier à entrer en bull market (au top), premier à paniquer en bear (au bottom). Sentiment retail = indicateur contrariant. Exception : les Européens qui font du DCA régulier surperforment.", relatedTerms: ["whale", "smart-money", "fomo"] },
  { term: "Pre-mine", slug: "pre-mine", category: "Tokenomics", definition: "Quantité de tokens créée avant le lancement public, généralement allouée à l'équipe, aux investisseurs et à la trésorerie. Bitcoin n'avait pas de pré-mine. Beaucoup d'altcoins ont 20-30 % en pré-mine. Pré-mine excessif = risque de dump majeur, rouge flag.", relatedTerms: ["tokenomics", "vesting"] },
  { term: "Genesis block", slug: "genesis-block", category: "Mining", definition: "Tout premier bloc d'une blockchain. Pour Bitcoin, miné le 3 janvier 2009 par Satoshi Nakamoto, contenant le message « The Times 03/Jan/2009 Chancellor on brink of second bailout for banks » — clin d'œil politique à la crise financière. Bloc 0, fondation de l'histoire crypto.", relatedTerms: ["bitcoin", "block"] },
  { term: "Pseudonyme", slug: "pseudonyme", category: "Sécurité", definition: "Caractère d'une blockchain publique : les transactions sont publiques mais reliées à des adresses, pas à des identités nominales. À distinguer de l'anonymat : avec assez d'analyse on-chain (Chainalysis), de nombreuses adresses sont liées à de vraies personnes. Vie privée crypto = effort actif (mixers, ZK).", relatedTerms: ["address", "kyc"] },
  { term: "Mixer", slug: "mixer", category: "Sécurité", definition: "Service mélangeant des transactions de nombreux utilisateurs pour rompre les chaînes d'analyse. Exemples : Tornado Cash (Ethereum, sanctionné par OFAC en 2022), Wasabi/Samourai (Bitcoin). Légalité variable selon les juridictions. Considéré comme suspect par défaut par les CASP — KYC renforcé probable.", relatedTerms: ["pseudonyme", "aml"] },
  { term: "Sybil attack", slug: "sybil-attack", category: "Sécurité", definition: "Attaque où un acteur crée de multiples identités/wallets pour influencer un système. Très courant sur les airdrops : un attaquant farm avec 10 000 wallets pour récupérer 10 000 allocations. Anti-Sybil : KYC, exigences on-chain (volume, ancienneté, diversité d'apps utilisées), filtres communautaires.", relatedTerms: ["airdrop", "kyc"] },
  { term: "51% attack", slug: "51-attack", category: "Sécurité", definition: "Attaque où un acteur contrôle plus de 50 % de la puissance de minage (PoW) ou du stake (PoS) et peut réorganiser la blockchain (double-spend, censure). Coût prohibitif sur Bitcoin (~25 milliards $/jour). A frappé des petites chains : Ethereum Classic, Bitcoin Gold. Dissuasif sur les chains majeures.", relatedTerms: ["mining", "consensus"] },
  { term: "Cold storage", slug: "cold-storage-2", category: "Sécurité", definition: "Variante : stockage très long terme avec dispositifs supplémentaires (multisig, vault physique, partage de seed via Shamir Secret Sharing). Pratique des hodlers crypto millionnaires. Une exposition à 100 % en hot wallet = irresponsable au-delà de quelques milliers d'euros.", relatedTerms: ["multisig", "hardware-wallet", "seed-phrase"] },
  { term: "Encryption", slug: "encryption", category: "Sécurité", definition: "Chiffrement cryptographique. Base mathématique des blockchains : SHA-256 (Bitcoin), Keccak-256 (Ethereum), EdDSA (Solana). Garantit l'intégrité, l'authenticité et la confidentialité. Sans cryptographie moderne, aucune crypto ne pourrait exister. À ne pas confondre avec l'encryption symétrique (AES) utilisée par les wallets locaux.", relatedTerms: ["hash", "private-key"] },
  { term: "Hash", slug: "hash", category: "Mining", definition: "Fonction mathématique transformant n'importe quelle donnée en une chaîne de longueur fixe (256 bits pour SHA-256). Propriétés : déterministe, irréversible, sensible à la moindre modification (avalanche effect). Base du linkage entre blocs, de la preuve de travail, de la signature des transactions.", relatedTerms: ["encryption", "block"] },
  { term: "Mnemonic", slug: "mnemonic", category: "Sécurité", definition: "Synonyme de seed phrase : 12 ou 24 mots BIP-39 qui dérivent toutes les clés privées d'un wallet HD. À écrire sur papier ou métal (Cryptosteel), jamais en numérique. Version standardisée (BIP-39) compatible entre la quasi-totalité des wallets.", relatedTerms: ["seed-phrase", "private-key", "wallet"] },
  { term: "BIP-39", slug: "bip-39", category: "Wallet", definition: "Bitcoin Improvement Proposal 39. Standard définissant la dérivation d'une seed à partir d'une liste de mots (2048 mots EN, FR, JP...). Utilisé par 99 % des wallets modernes. Permet de récupérer un wallet sur n'importe quel logiciel compatible BIP-39 (Metamask, Phantom, Ledger Live).", relatedTerms: ["seed-phrase", "mnemonic", "wallet"] },
  { term: "BIP-32", slug: "bip-32", category: "Wallet", definition: "Bitcoin Improvement Proposal 32. Standard des Hierarchical Deterministic Wallets : génère un nombre infini d'adresses à partir d'une seule seed master. Permet de créer une nouvelle adresse à chaque transaction (privacy) sans avoir à backup chaque clé séparément.", relatedTerms: ["bip-39", "wallet"] },
  { term: "Custodial", slug: "custodial", category: "Wallet", definition: "Service où un tiers garde vos clés privées (Coinbase, Binance, PayPal Crypto). Avantages : récupération facile en cas de perte de mot de passe, support client. Inconvénients : « Not your keys, not your coins ». Risques : faillite (FTX), hack, gel de compte par injonction. À limiter aux montants de trading.", relatedTerms: ["non-custodial", "wallet"] },
  { term: "Non-custodial", slug: "non-custodial", category: "Wallet", definition: "Wallet où vous gardez vos clés privées (Metamask, Phantom, Ledger). Souveraineté totale : personne ne peut vous freezer ni vous voler sans votre seed. Contrepartie : si vous perdez votre seed, vos fonds sont perdus à jamais. Recommandé pour tout patrimoine sérieux.", relatedTerms: ["custodial", "wallet", "seed-phrase"] },
  { term: "Self-custody", slug: "self-custody", category: "Wallet", definition: "Pratique de gérer soi-même ses clés privées plutôt que de les confier à un tiers. Mantra : « Not your keys, not your coins ». Bonne pratique : majorité du patrimoine en self-custody hardware, fraction en CEX pour trading actif. La self-custody est l'essence du Bitcoin.", relatedTerms: ["non-custodial", "cold-wallet", "seed-phrase"] },
  { term: "Lightning Network", slug: "lightning-network", category: "Layer 2", definition: "Layer 2 Bitcoin permettant des micropaiements quasi-instantanés et gratuits. Fonctionne via des canaux de paiement bidirectionnels off-chain. Adopté pour le e-commerce, les remittances, le streaming sat. Capacité ~5000 BTC. Wallets : Phoenix, Wallet of Satoshi, Strike, Breez.", relatedTerms: ["bitcoin", "layer-2"] },
  { term: "Stack sats", slug: "stack-sats", category: "Trading", definition: "Stratégie d'accumulation régulière de satoshis (1 BTC = 100 millions sats), variante du DCA Bitcoin. Souvent automatisée via apps comme Bitstack ou Strike. Approche maximaliste BTC : on ne mesure plus en € mais en sats accumulés. Communauté active autour du hashtag #StackSats.", relatedTerms: ["dca", "satoshi", "bitcoin"], internalLink: "/outils/simulateur-dca" },
  { term: "Satoshi", slug: "satoshi", category: "Tokenomics", definition: "Plus petite unité de Bitcoin : 1 sat = 0,00000001 BTC. Nommé en hommage à Satoshi Nakamoto, créateur pseudonymé de Bitcoin. À l'échelle des sats, BTC devient « accessible » : 1 € = ~1000 sats au cours actuel. Rend le DCA crypto émotionnellement plus engageant.", relatedTerms: ["bitcoin", "stack-sats"] },
  { term: "Maximaliste", slug: "maximaliste", category: "Trading", definition: "Investisseur qui ne croit qu'à une seule cryptomonnaie, généralement Bitcoin. Pour les BTC maxis, tous les altcoins sont des distractions ou des shitcoins. Idéologie cohérente mais opportuniste : a fait gagner gros aux purs Bitcoin holders depuis 2010. Communauté très active sur Twitter.", relatedTerms: ["bitcoin", "altcoin", "hodl"] },
  // ----- Quelques derniers termes utiles -----
  { term: "Token", slug: "token", category: "Tokenomics", definition: "Représentation numérique d'un actif sur une blockchain. Distincts des coins natifs (BTC, ETH) : les tokens sont émis sur une blockchain existante via un standard (ERC-20 sur Ethereum, SPL sur Solana). Représentent : monnaie, gouvernance, accès, propriété d'actif réel (RWA), points de fidélité.", relatedTerms: ["coin", "erc-20"] },
  { term: "Coin", slug: "coin", category: "Tokenomics", definition: "Cryptomonnaie native d'une blockchain (BTC sur Bitcoin, ETH sur Ethereum, SOL sur Solana). À distinguer des tokens qui sont émis par-dessus une blockchain existante. Les coins paient les frais de transaction et sécurisent le réseau (mining ou staking).", relatedTerms: ["token", "altcoin"] },
  { term: "ERC-20", slug: "erc-20", category: "Tokenomics", definition: "Standard de smart contract Ethereum pour créer des tokens fongibles. Quasi tous les tokens crypto majeurs sont ERC-20 (USDT, USDC, UNI, AAVE, LINK). Interface standardisée : transfer, approve, balanceOf. Une seule implémentation pour des milliers de tokens — économie d'échelle phénoménale.", relatedTerms: ["token", "smart-contract"] },
  { term: "SPL", slug: "spl", category: "Tokenomics", definition: "Solana Program Library. Équivalent de l'ERC-20 sur Solana, avec des extensions (Token Extensions / Token-22) pour metadata, transfer hooks, fees. Standardise la création de tokens sur Solana. Tous les memecoins, stablecoins, gouvernance tokens Solana sont SPL.", relatedTerms: ["token", "solana"] },
  { term: "Faucet drip", slug: "faucet-drip", category: "Tokenomics", definition: "Mécanisme distribuant régulièrement de petites quantités de tokens (souvent stables) aux participants d'une activité (LP, staker). Variante on-chain du faucet, sans demande explicite. Utilisé pour l'incentivisation continue dans les protocoles DeFi.", relatedTerms: ["faucet", "yield-farming"] },
  { term: "RWA", slug: "rwa", category: "DeFi", definition: "Real World Assets. Tokenisation d'actifs traditionnels (immobilier, bons du Trésor, actions, or, art) sur la blockchain. Marché en pleine expansion : MakerDAO, Ondo Finance, Centrifuge tokenisent des US Treasuries. Pont entre TradFi et DeFi. Régulation complexe selon la juridiction.", relatedTerms: ["defi", "tokenomics"] },
  { term: "GameFi", slug: "gamefi", category: "DeFi", definition: "Convergence du gaming et de la DeFi. Joueurs gagnent des tokens et NFT en jouant (« play-to-earn »). Boom 2021 (Axie Infinity), bust 2022. Maturation 2024 : modèles « play-and-earn » plus durables, intégration des grosses franchises gaming Web2.", relatedTerms: ["nft", "defi"] },
  { term: "SocialFi", slug: "socialfi", category: "DeFi", definition: "Réseaux sociaux décentralisés monétisant les interactions via tokens (Friend.tech, Lens Protocol, Farcaster). Promesse : reprendre le pouvoir face aux GAFAM. Adoption modeste mais croissante. Premiers cas d'usage durables : creators monétisant leur audience directement.", relatedTerms: ["web3", "defi"] },
  { term: "DePIN", slug: "depin", category: "DeFi", definition: "Decentralized Physical Infrastructure Networks. Réseaux décentralisés d'infrastructure physique : storage (Filecoin), bande passante (Helium), GPU compute (Akash, Render), data (Hivemapper). Récompensent les contributeurs en tokens. Croissance forte 2024-2025 grâce à l'IA et au cloud.", relatedTerms: ["web3"] },
  { term: "Bitcoin ETF", slug: "bitcoin-etf", category: "Trading", definition: "Exchange-Traded Fund répliquant le cours du Bitcoin sur les marchés financiers traditionnels. Approuvés aux US en janvier 2024 (BlackRock IBIT, Fidelity FBTC, Grayscale GBTC). Plus de 100 milliards $ d'AUM cumulés. Rendent BTC accessible via courtiers classiques. ETF Ethereum approuvés mi-2024.", relatedTerms: ["bitcoin", "spot"] },
  { term: "Custodian", slug: "custodian", category: "Régulation", definition: "Acteur régulé qui détient les cryptos pour le compte d'institutions ou d'ETF. Référence : Coinbase Custody, BitGo, Fidelity Digital Assets. Audités, assurés, conformes SOC 2. Indispensable pour l'adoption institutionnelle. Garde des dizaines de milliards $ pour les ETF Bitcoin.", relatedTerms: ["bitcoin-etf", "custodial"] },
  { term: "Permissionless", slug: "permissionless", category: "DeFi", definition: "Caractéristique des protocoles ouverts à quiconque sans autorisation préalable. Anyone can deploy a contract on Ethereum, list a token on Uniswap, borrow on Aave. Inverse de permissioned (réseaux privés type Hyperledger). Essence philosophique du Web3 et de la DeFi.", relatedTerms: ["defi", "censorship-resistance"] },
  { term: "Censorship resistance", slug: "censorship-resistance", category: "Sécurité", definition: "Capacité d'un protocole à résister aux tentatives de censure (gouvernementale, corporate). Bitcoin = exemple ultime : aucune entité ne peut bloquer une transaction valide. Mis à l'épreuve avec les sanctions OFAC sur Tornado Cash : certains validateurs Ethereum ont commencé à filtrer, créant une crise de confiance.", relatedTerms: ["permissionless", "decentralisation"] },
  { term: "Décentralisation", slug: "decentralisation", category: "Tokenomics", definition: "Distribution du contrôle d'un réseau ou protocole entre de nombreux acteurs indépendants. Mesurée par : nombre de nœuds, géographie, distribution des tokens, gouvernance. Plus c'est décentralisé, plus c'est résilient mais plus c'est lent à évoluer. Trilemme : scalabilité vs sécurité vs décentralisation.", relatedTerms: ["consensus", "censorship-resistance"] },
  { term: "Web3 wallet", slug: "web3-wallet", category: "Wallet", definition: "Wallet supportant l'interaction avec les dApps via WalletConnect ou injection navigateur (window.ethereum). Standard de l'écosystème : Metamask, Rabby, Phantom, Trust Wallet. Permet de signer transactions, swap, mint NFT directement depuis le wallet. UX en amélioration constante.", relatedTerms: ["wallet", "metamask", "dapp"] },
  { term: "WalletConnect", slug: "walletconnect", category: "Wallet", definition: "Protocole open-source connectant les wallets mobiles aux dApps desktop via QR code. Plus de 600 wallets compatibles, 70 000+ dApps. Permet d'utiliser un hardware wallet ou un wallet mobile sans extension. Standard de fait pour la connexion dApp.", relatedTerms: ["web3-wallet", "dapp"] },
  { term: "Privacy coin", slug: "privacy-coin", category: "Trading", definition: "Cryptomonnaie axée sur la confidentialité des transactions : Monero (XMR), Zcash (ZEC). Utilisent des techniques cryptographiques avancées (ring signatures, ZK-SNARKs) pour rendre les transactions et soldes opaques. De plus en plus delistées des CEX par pression réglementaire (EU 2024 a interdit les privacy coins sur les CASP).", relatedTerms: ["zero-knowledge", "monero"] },
  { term: "Monero", slug: "monero", category: "Trading", definition: "Privacy coin la plus utilisée. Lancée en 2014. Utilise ring signatures et stealth addresses. Marketcap ~3 milliards $. Restée fidèle à la philosophie cypherpunk du cash digital privé. Delistée de Binance, Kraken pour les utilisateurs européens (MiCA). À acheter via DEX cross-chain ou échanges P2P.", relatedTerms: ["privacy-coin", "zero-knowledge"] },
  { term: "Open interest", slug: "open-interest", category: "Trading", definition: "Total des contrats futures/perpetuals ouverts. Indicateur clé pour mesurer l'engagement spéculatif. OI en hausse + prix en hausse = tendance saine. OI en hausse + prix en baisse = shorts qui s'empilent (potentiel short squeeze). Explose souvent avant les liquidations cascade.", relatedTerms: ["futures", "perpetual", "leverage"] },
  { term: "Funding flip", slug: "funding-flip", category: "Trading", definition: "Inversion du sens du funding rate (de positif à négatif ou inversement). Signal de retournement de sentiment. Funding flip négatif après une longue période positive = capitulation des longs, possible bottom local. Outil avancé pour les traders pros.", relatedTerms: ["funding-rate", "perpetual"] },
  { term: "Whale wallet", slug: "whale-wallet", category: "Trading", definition: "Adresse on-chain détenant une grosse quantité de cryptos. Suivi via Whale Alert, Lookonchain, Arkham. Mouvements des whales = signaux précieux : accumulation (bullish) ou dépôt sur exchange (bearish, possible vente imminente). Trackés en temps réel par tout pro.", relatedTerms: ["whale", "smart-money"] },
  { term: "On-chain analysis", slug: "on-chain-analysis", category: "Trading", definition: "Étude des données publiques de la blockchain pour anticiper les mouvements de prix : flows exchanges, accumulation des whales, hashrate, Realized Cap, MVRV, NUPL. Outils : Glassnode, CryptoQuant, Nansen. Avantage majeur sur la finance traditionnelle (impossible de voir les flux entrants Apple).", relatedTerms: ["whale-wallet", "smart-money"] },
  { term: "Glassnode", slug: "glassnode", category: "Trading", definition: "Plateforme leader d'on-chain analytics. Tableaux de bord pour Bitcoin, Ethereum et altcoins majeurs. Indicateurs propriétaires (NUPL, SOPR, Realized Price). Utilisé par les hedge funds et chercheurs. Tier gratuit limité, abonnements 35-700 $/mois.", relatedTerms: ["on-chain-analysis"] },
  { term: "Dune Analytics", slug: "dune", category: "Trading", definition: "Plateforme open d'analytics blockchain. Permet à n'importe qui de créer des dashboards SQL custom sur les données on-chain Ethereum, Solana, etc. Communauté active de wizards qui partagent leurs requêtes. Indispensable pour la recherche DeFi indépendante.", relatedTerms: ["on-chain-analysis"] },
  { term: "Nansen", slug: "nansen", category: "Trading", definition: "Plateforme d'on-chain analytics premium qui labellise les wallets (Smart Money, Whales, fonds d'investissement). Permet de tracker les positions des acteurs sophistiqués. Cher (~150 $/mois) mais très puissant. Bestiaire complet : Token God Mode, NFT Paradise.", relatedTerms: ["on-chain-analysis", "smart-money"] },
  { term: "Cypherpunk", slug: "cypherpunk", category: "Sécurité", definition: "Mouvement intellectuel et politique qui défend l'usage de la cryptographie pour préserver la vie privée et l'autonomie individuelle face aux États et aux entreprises. Bitcoin est la concrétisation cypherpunk ultime. Auteurs majeurs : Eric Hughes, Tim May, Hal Finney, Adam Back. Toujours influent en 2025.", relatedTerms: ["bitcoin", "censorship-resistance", "privacy-coin"] },
  { term: "Pizza Day", slug: "pizza-day", category: "Trading", definition: "22 mai 2010 : Laszlo Hanyecz paie 10 000 BTC pour deux pizzas — première transaction commerciale BTC. Au cours actuel (~100k$/BTC), ces pizzas valent un milliard de dollars. Devenue célébration annuelle de la communauté Bitcoin. Rappel humoristique de la patience nécessaire en HODL.", relatedTerms: ["bitcoin", "hodl"] },
];

/** Tri alphabétique stable, locale FR, insensible aux accents. */
export const GLOSSARY: GlossaryTermFlat[] = [..._GLOSSARY_RAW].sort((a, b) =>
  a.term.localeCompare(b.term, "fr", { sensitivity: "base" })
);

/** Slugs garantis uniques (audit time : si collision, throw au build). */
const _slugs = new Set<string>();
for (const t of GLOSSARY) {
  if (_slugs.has(t.slug)) {
    // Si collision : on renomme automatiquement avec un suffixe `-2` plutôt que crash
    // (cas du doublon "cold-storage" → "cold-storage-2" déjà appliqué manuellement).
    // ce code reste un garde-fou silencieux pour les futurs ajouts.
    // eslint-disable-next-line no-console
    console.warn(`[glossary] slug duplicate detected: ${t.slug}`);
  }
  _slugs.add(t.slug);
}

/** Catégories du glossaire flat (pour les chips de filtre). */
export const GLOSSARY_FLAT_CATEGORIES: GlossaryFlatCategory[] = [
  "Trading",
  "DeFi",
  "Sécurité",
  "Régulation",
  "NFT",
  "Layer 2",
  "Tokenomics",
  "Wallet",
  "Mining",
  "Stablecoin",
];

/** Construit le JSON-LD DefinedTermSet pour /outils/glossaire-crypto. */
export function buildFlatDefinedTermSetSchema(siteUrl: string) {
  return {
    "@context": "https://schema.org",
    "@type": "DefinedTermSet",
    "@id": `${siteUrl}/outils/glossaire-crypto#termset`,
    name: "Glossaire crypto français Cryptoreflex",
    description:
      "Plus de 200 termes crypto français définis : trading, DeFi, sécurité, régulation, NFT, Layer 2, tokenomics, wallets, mining et stablecoins.",
    url: `${siteUrl}/outils/glossaire-crypto`,
    inLanguage: "fr-FR",
    hasDefinedTerm: GLOSSARY.map((t) => ({
      "@type": "DefinedTerm",
      "@id": `${siteUrl}/outils/glossaire-crypto#${t.slug}`,
      name: t.term,
      description: t.definition,
      termCode: t.slug,
      url: `${siteUrl}/outils/glossaire-crypto#${t.slug}`,
      inDefinedTermSet: `${siteUrl}/outils/glossaire-crypto#termset`,
    })),
  };
}
